                double vyil_03 = gouty[0]*dm_jk_00 + gouty[1]*dm_jk_01 + gouty[2]*dm_jk_02 + gouty[3]*dm_jk_03 + gouty[4]*dm_jk_04 + gouty[5]*dm_jk_05;
                atomicAdd(vk_y+(i0+0)*nao+(l0+3), vyil_03);
                double vzil_03 = goutz[0]*dm_jk_00 + goutz[1]*dm_jk_01 + goutz[2]*dm_jk_02 + goutz[3]*dm_jk_03 + goutz[4]*dm_jk_04 + goutz[5]*dm_jk_05;
                atomicAdd(vk_z+(i0+0)*nao+(l0+3), vzil_03);
                double vxil_04 = goutx[6]*dm_jk_00 + goutx[7]*dm_jk_01 + goutx[8]*dm_jk_02 + goutx[9]*dm_jk_03 + goutx[10]*dm_jk_04 + goutx[11]*dm_jk_05;
                atomicAdd(vk_x+(i0+0)*nao+(l0+4), vxil_04);
                double vyil_04 = gouty[6]*dm_jk_00 + gouty[7]*dm_jk_01 + gouty[8]*dm_jk_02 + gouty[9]*dm_jk_03 + gouty[10]*dm_jk_04 + gouty[11]*dm_jk_05;
                atomicAdd(vk_y+(i0+0)*nao+(l0+4), vyil_04);
                double vzil_04 = goutz[6]*dm_jk_00 + goutz[7]*dm_jk_01 + goutz[8]*dm_jk_02 + goutz[9]*dm_jk_03 + goutz[10]*dm_jk_04 + goutz[11]*dm_jk_05;
                atomicAdd(vk_z+(i0+0)*nao+(l0+4), vzil_04);
                double vxil_05 = goutx[12]*dm_jk_00 + goutx[13]*dm_jk_01 + goutx[14]*dm_jk_02 + goutx[15]*dm_jk_03 + goutx[16]*dm_jk_04 + goutx[17]*dm_jk_05;
                atomicAdd(vk_x+(i0+0)*nao+(l0+5), vxil_05);
                double vyil_05 = gouty[12]*dm_jk_00 + gouty[13]*dm_jk_01 + gouty[14]*dm_jk_02 + gouty[15]*dm_jk_03 + gouty[16]*dm_jk_04 + gouty[17]*dm_jk_05;
                atomicAdd(vk_y+(i0+0)*nao+(l0+5), vyil_05);
                double vzil_05 = goutz[12]*dm_jk_00 + goutz[13]*dm_jk_01 + goutz[14]*dm_jk_02 + goutz[15]*dm_jk_03 + goutz[16]*dm_jk_04 + goutz[17]*dm_jk_05;
                atomicAdd(vk_z+(i0+0)*nao+(l0+5), vzil_05);
                double dm_jl_03 = dm[(j0+0)*nao+(l0+3)];
                double dm_jl_04 = dm[(j0+0)*nao+(l0+4)];
                double dm_jl_05 = dm[(j0+0)*nao+(l0+5)];
                double vxik_00 = goutx[0]*dm_jl_03 + goutx[6]*dm_jl_04 + goutx[12]*dm_jl_05;
                atomicAdd(vk_x+(i0+0)*nao+(k0+0), vxik_00);
                double vyik_00 = gouty[0]*dm_jl_03 + gouty[6]*dm_jl_04 + gouty[12]*dm_jl_05;
                atomicAdd(vk_y+(i0+0)*nao+(k0+0), vyik_00);
                double vzik_00 = goutz[0]*dm_jl_03 + goutz[6]*dm_jl_04 + goutz[12]*dm_jl_05;
                atomicAdd(vk_z+(i0+0)*nao+(k0+0), vzik_00);
                double vxik_01 = goutx[1]*dm_jl_03 + goutx[7]*dm_jl_04 + goutx[13]*dm_jl_05;
                atomicAdd(vk_x+(i0+0)*nao+(k0+1), vxik_01);
                double vyik_01 = gouty[1]*dm_jl_03 + gouty[7]*dm_jl_04 + gouty[13]*dm_jl_05;
                atomicAdd(vk_y+(i0+0)*nao+(k0+1), vyik_01);
                double vzik_01 = goutz[1]*dm_jl_03 + goutz[7]*dm_jl_04 + goutz[13]*dm_jl_05;
                atomicAdd(vk_z+(i0+0)*nao+(k0+1), vzik_01);
                double vxik_02 = goutx[2]*dm_jl_03 + goutx[8]*dm_jl_04 + goutx[14]*dm_jl_05;
                atomicAdd(vk_x+(i0+0)*nao+(k0+2), vxik_02);
                double vyik_02 = gouty[2]*dm_jl_03 + gouty[8]*dm_jl_04 + gouty[14]*dm_jl_05;
                atomicAdd(vk_y+(i0+0)*nao+(k0+2), vyik_02);
                double vzik_02 = goutz[2]*dm_jl_03 + goutz[8]*dm_jl_04 + goutz[14]*dm_jl_05;
                atomicAdd(vk_z+(i0+0)*nao+(k0+2), vzik_02);
                double vxik_03 = goutx[3]*dm_jl_03 + goutx[9]*dm_jl_04 + goutx[15]*dm_jl_05;
                atomicAdd(vk_x+(i0+0)*nao+(k0+3), vxik_03);
                double vyik_03 = gouty[3]*dm_jl_03 + gouty[9]*dm_jl_04 + gouty[15]*dm_jl_05;
                atomicAdd(vk_y+(i0+0)*nao+(k0+3), vyik_03);
                double vzik_03 = goutz[3]*dm_jl_03 + goutz[9]*dm_jl_04 + goutz[15]*dm_jl_05;
                atomicAdd(vk_z+(i0+0)*nao+(k0+3), vzik_03);
                double vxik_04 = goutx[4]*dm_jl_03 + goutx[10]*dm_jl_04 + goutx[16]*dm_jl_05;
                atomicAdd(vk_x+(i0+0)*nao+(k0+4), vxik_04);
                double vyik_04 = gouty[4]*dm_jl_03 + gouty[10]*dm_jl_04 + gouty[16]*dm_jl_05;
                atomicAdd(vk_y+(i0+0)*nao+(k0+4), vyik_04);
                double vzik_04 = goutz[4]*dm_jl_03 + goutz[10]*dm_jl_04 + goutz[16]*dm_jl_05;
                atomicAdd(vk_z+(i0+0)*nao+(k0+4), vzik_04);
                double vxik_05 = goutx[5]*dm_jl_03 + goutx[11]*dm_jl_04 + goutx[17]*dm_jl_05;
                atomicAdd(vk_x+(i0+0)*nao+(k0+5), vxik_05);
                double vyik_05 = gouty[5]*dm_jl_03 + gouty[11]*dm_jl_04 + gouty[17]*dm_jl_05;
                atomicAdd(vk_y+(i0+0)*nao+(k0+5), vyik_05);
                double vzik_05 = goutz[5]*dm_jl_03 + goutz[11]*dm_jl_04 + goutz[17]*dm_jl_05;
                atomicAdd(vk_z+(i0+0)*nao+(k0+5), vzik_05);
                double dm_ik_00 = dm[(i0+0)*nao+(k0+0)];
                double dm_ik_01 = dm[(i0+0)*nao+(k0+1)];
                double dm_ik_02 = dm[(i0+0)*nao+(k0+2)];
                double dm_ik_03 = dm[(i0+0)*nao+(k0+3)];
                double dm_ik_04 = dm[(i0+0)*nao+(k0+4)];
                double dm_ik_05 = dm[(i0+0)*nao+(k0+5)];
                double vxjl_03 = goutx[0]*dm_ik_00 + goutx[1]*dm_ik_01 + goutx[2]*dm_ik_02 + goutx[3]*dm_ik_03 + goutx[4]*dm_ik_04 + goutx[5]*dm_ik_05;
                atomicAdd(vk_x+(j0+0)*nao+(l0+3), vxjl_03);
                double vyjl_03 = gouty[0]*dm_ik_00 + gouty[1]*dm_ik_01 + gouty[2]*dm_ik_02 + gouty[3]*dm_ik_03 + gouty[4]*dm_ik_04 + gouty[5]*dm_ik_05;
                atomicAdd(vk_y+(j0+0)*nao+(l0+3), vyjl_03);
                double vzjl_03 = goutz[0]*dm_ik_00 + goutz[1]*dm_ik_01 + goutz[2]*dm_ik_02 + goutz[3]*dm_ik_03 + goutz[4]*dm_ik_04 + goutz[5]*dm_ik_05;
                atomicAdd(vk_z+(j0+0)*nao+(l0+3), vzjl_03);
                double vxjl_04 = goutx[6]*dm_ik_00 + goutx[7]*dm_ik_01 + goutx[8]*dm_ik_02 + goutx[9]*dm_ik_03 + goutx[10]*dm_ik_04 + goutx[11]*dm_ik_05;
                atomicAdd(vk_x+(j0+0)*nao+(l0+4), vxjl_04);
                double vyjl_04 = gouty[6]*dm_ik_00 + gouty[7]*dm_ik_01 + gouty[8]*dm_ik_02 + gouty[9]*dm_ik_03 + gouty[10]*dm_ik_04 + gouty[11]*dm_ik_05;
                atomicAdd(vk_y+(j0+0)*nao+(l0+4), vyjl_04);
                double vzjl_04 = goutz[6]*dm_ik_00 + goutz[7]*dm_ik_01 + goutz[8]*dm_ik_02 + goutz[9]*dm_ik_03 + goutz[10]*dm_ik_04 + goutz[11]*dm_ik_05;
                atomicAdd(vk_z+(j0+0)*nao+(l0+4), vzjl_04);
                double vxjl_05 = goutx[12]*dm_ik_00 + goutx[13]*dm_ik_01 + goutx[14]*dm_ik_02 + goutx[15]*dm_ik_03 + goutx[16]*dm_ik_04 + goutx[17]*dm_ik_05;
                atomicAdd(vk_x+(j0+0)*nao+(l0+5), vxjl_05);
                double vyjl_05 = gouty[12]*dm_ik_00 + gouty[13]*dm_ik_01 + gouty[14]*dm_ik_02 + gouty[15]*dm_ik_03 + gouty[16]*dm_ik_04 + gouty[17]*dm_ik_05;
                atomicAdd(vk_y+(j0+0)*nao+(l0+5), vyjl_05);
                double vzjl_05 = goutz[12]*dm_ik_00 + goutz[13]*dm_ik_01 + goutz[14]*dm_ik_02 + goutz[15]*dm_ik_03 + goutz[16]*dm_ik_04 + goutz[17]*dm_ik_05;
                atomicAdd(vk_z+(j0+0)*nao+(l0+5), vzjl_05);
                double dm_il_03 = dm[(i0+0)*nao+(l0+3)];
                double dm_il_04 = dm[(i0+0)*nao+(l0+4)];
                double dm_il_05 = dm[(i0+0)*nao+(l0+5)];
                double vxjk_00 = goutx[0]*dm_il_03 + goutx[6]*dm_il_04 + goutx[12]*dm_il_05;
                atomicAdd(vk_x+(j0+0)*nao+(k0+0), vxjk_00);
                double vyjk_00 = gouty[0]*dm_il_03 + gouty[6]*dm_il_04 + gouty[12]*dm_il_05;
                atomicAdd(vk_y+(j0+0)*nao+(k0+0), vyjk_00);
                double vzjk_00 = goutz[0]*dm_il_03 + goutz[6]*dm_il_04 + goutz[12]*dm_il_05;
                atomicAdd(vk_z+(j0+0)*nao+(k0+0), vzjk_00);
                double vxjk_01 = goutx[1]*dm_il_03 + goutx[7]*dm_il_04 + goutx[13]*dm_il_05;
                atomicAdd(vk_x+(j0+0)*nao+(k0+1), vxjk_01);
                double vyjk_01 = gouty[1]*dm_il_03 + gouty[7]*dm_il_04 + gouty[13]*dm_il_05;
                atomicAdd(vk_y+(j0+0)*nao+(k0+1), vyjk_01);
                double vzjk_01 = goutz[1]*dm_il_03 + goutz[7]*dm_il_04 + goutz[13]*dm_il_05;
                atomicAdd(vk_z+(j0+0)*nao+(k0+1), vzjk_01);
                double vxjk_02 = goutx[2]*dm_il_03 + goutx[8]*dm_il_04 + goutx[14]*dm_il_05;
                atomicAdd(vk_x+(j0+0)*nao+(k0+2), vxjk_02);
                double vyjk_02 = gouty[2]*dm_il_03 + gouty[8]*dm_il_04 + gouty[14]*dm_il_05;
                atomicAdd(vk_y+(j0+0)*nao+(k0+2), vyjk_02);
                double vzjk_02 = goutz[2]*dm_il_03 + goutz[8]*dm_il_04 + goutz[14]*dm_il_05;
                atomicAdd(vk_z+(j0+0)*nao+(k0+2), vzjk_02);
                double vxjk_03 = goutx[3]*dm_il_03 + goutx[9]*dm_il_04 + goutx[15]*dm_il_05;
                atomicAdd(vk_x+(j0+0)*nao+(k0+3), vxjk_03);
                double vyjk_03 = gouty[3]*dm_il_03 + gouty[9]*dm_il_04 + gouty[15]*dm_il_05;
                atomicAdd(vk_y+(j0+0)*nao+(k0+3), vyjk_03);
                double vzjk_03 = goutz[3]*dm_il_03 + goutz[9]*dm_il_04 + goutz[15]*dm_il_05;
                atomicAdd(vk_z+(j0+0)*nao+(k0+3), vzjk_03);
                double vxjk_04 = goutx[4]*dm_il_03 + goutx[10]*dm_il_04 + goutx[16]*dm_il_05;
                atomicAdd(vk_x+(j0+0)*nao+(k0+4), vxjk_04);
                double vyjk_04 = gouty[4]*dm_il_03 + gouty[10]*dm_il_04 + gouty[16]*dm_il_05;
                atomicAdd(vk_y+(j0+0)*nao+(k0+4), vyjk_04);
                double vzjk_04 = goutz[4]*dm_il_03 + goutz[10]*dm_il_04 + goutz[16]*dm_il_05;
                atomicAdd(vk_z+(j0+0)*nao+(k0+4), vzjk_04);
                double vxjk_05 = goutx[5]*dm_il_03 + goutx[11]*dm_il_04 + goutx[17]*dm_il_05;
                atomicAdd(vk_x+(j0+0)*nao+(k0+5), vxjk_05);
                double vyjk_05 = gouty[5]*dm_il_03 + gouty[11]*dm_il_04 + gouty[17]*dm_il_05;
                atomicAdd(vk_y+(j0+0)*nao+(k0+5), vyjk_05);
                double vzjk_05 = goutz[5]*dm_il_03 + goutz[11]*dm_il_04 + goutz[17]*dm_il_05;
                atomicAdd(vk_z+(j0+0)*nao+(k0+5), vzjk_05);
            }
        }
    }
}
}

__global__ static
void rys_vjk_ip1_0100(RysIntEnvVars envs, JKMatrix jk, BoundsInfo bounds,
                    float *q_cond_ij, float *q_cond_kl, float dm_penalty,
                    float *s_cond_ij, float *s_cond_kl, float *diffuse_exps,
                    uint32_t *pool, int *head)
{
    int sq_id = threadIdx.x;
    int nbas = envs.nbas;
    int *bas = envs.bas;
    double *env = envs.env;
    int nroots = bounds.nroots;
    int nsq_per_block = blockDim.x;
    int gout_stride = blockDim.y;
    extern __shared__ double shared_memory[];
    double *rw = shared_memory + sq_id;
    double *cicj_cache = shared_memory + nsq_per_block * (nroots*2);
    int t_id = threadIdx.y * nsq_per_block + threadIdx.x;
    int threads = nsq_per_block * gout_stride;

    uint32_t *bas_kl_idx = pool + blockIdx.x * QUEUE_DEPTH;
    __shared__ int ntasks, pair_ij, pair_kl0;
while (1) {
    __syncthreads();
    __shared__ int ish, jsh;
    if (sq_id == 0) {
        int task_id = atomicAdd(head, 1);
        int batch_kl = task_id / bounds.npairs_ij;
        pair_ij = task_id - bounds.npairs_ij * batch_kl;
        pair_kl0 = batch_kl * (QUEUE_DEPTH - 512);
        uint32_t bas_ij = bounds.pair_ij_mapping[pair_ij];
        ish = bas_ij / nbas;
        jsh = bas_ij % nbas;
    }
    __syncthreads();
    if (pair_kl0 >= bounds.npairs_kl) {
        break;
    }
    if (jk.lr_factor != 0) {
        _fill_vjk_tasks_nosym(ntasks, pair_kl0, bas_kl_idx, pair_ij, ish, jsh,
                              q_cond_ij, q_cond_kl, dm_penalty, envs, bounds);
    } else {
        _fill_sr_vjk_tasks_nosym(ntasks, pair_kl0, bas_kl_idx, pair_ij, ish, jsh,
                                 q_cond_ij, q_cond_kl, dm_penalty,
                                 s_cond_ij, s_cond_kl, diffuse_exps, envs, bounds);
    }
    if (ntasks == 0) {
        continue;
    }
    __shared__ double ri[3];
    __shared__ double rjri[3];
    __shared__ double aij_cache[3];
    __shared__ int expi;
    __shared__ int expj;
    if (t_id == 0) {
        expi = bas[ish*BAS_SLOTS+PTR_EXP];
        expj = bas[jsh*BAS_SLOTS+PTR_EXP];
    }
    __syncthreads();
    if (t_id < 3) {
        int ri_ptr = bas[ish*BAS_SLOTS+PTR_BAS_COORD];
        int rj_ptr = bas[jsh*BAS_SLOTS+PTR_BAS_COORD];
        ri[t_id] = env[ri_ptr+t_id];
        rjri[t_id] = env[rj_ptr+t_id] - ri[t_id];
    }
    __syncthreads();
    double *ci = env + bas[ish*BAS_SLOTS+PTR_COEFF];
    double *cj = env + bas[jsh*BAS_SLOTS+PTR_COEFF];
    double xjxi = rjri[0];
    double yjyi = rjri[1];
    double zjzi = rjri[2];
    int iprim = bounds.iprim;
    int jprim = bounds.jprim;
    for (int ij = t_id; ij < iprim*jprim; ij += threads) {
        int ip = ij / jprim;
        int jp = ij % jprim;
        double ai = env[expi+ip];
        double aj = env[expj+jp];
        double aij = ai + aj;
        double theta_ij = ai * aj / aij;
        double rr_ij = xjxi*xjxi + yjyi*yjyi + zjzi*zjzi;
        double Kab = exp(-theta_ij * rr_ij);
        cicj_cache[ij] = ci[ip] * cj[jp] * Kab;
    }
    __syncthreads();
    for (int task_id = sq_id; task_id < ntasks+sq_id; task_id += nsq_per_block) {
        int iprim = bounds.iprim;
        int jprim = bounds.jprim;
        int kprim = bounds.kprim;
        int lprim = bounds.lprim;
        uint32_t bas_kl = bas_kl_idx[task_id];
        int ksh = bas_kl / nbas;
        int lsh = bas_kl % nbas;
        int expk = bas[ksh*BAS_SLOTS+PTR_EXP];
        int expl = bas[lsh*BAS_SLOTS+PTR_EXP];
        int ck = bas[ksh*BAS_SLOTS+PTR_COEFF];
        int cl = bas[lsh*BAS_SLOTS+PTR_COEFF];
        int rk = bas[ksh*BAS_SLOTS+PTR_BAS_COORD];
        int rl = bas[lsh*BAS_SLOTS+PTR_BAS_COORD];
        double xlxk = env[rl+0] - env[rk+0];
        double ylyk = env[rl+1] - env[rk+1];
        double zlzk = env[rl+2] - env[rk+2];
        double goutx[3];
        double gouty[3];
        double goutz[3];
        #pragma unroll
        for (int n = 0; n < 3; ++n) {
            goutx[n] = 0;
            gouty[n] = 0;
            goutz[n] = 0;
        }
        for (int klp = 0; klp < kprim*lprim; ++klp) {
            int kp = klp / lprim;
            int lp = klp % lprim;
            double ak = env[expk+kp];
            double al = env[expl+lp];
            double akl = ak + al;
            double al_akl = al / akl;
            double theta_kl = ak * al_akl;
            double fac_sym = PI_FAC;
            if (task_id < ntasks) {
                if (ksh == lsh) fac_sym *= .5;
            } else {
                fac_sym = 0;
            }
            double Kcd = exp(-theta_kl * (xlxk*xlxk+ylyk*ylyk+zlzk*zlzk));
            double ckcl = fac_sym * env[ck+kp] * env[cl+lp] * Kcd;
            for (int ijp = 0; ijp < iprim*jprim; ++ijp) {
                int ip = ijp / jprim;
                int jp = ijp % jprim;
                double ai = env[expi+ip];
                double aj = env[expj+jp];
                double aij = ai + aj;
                double aj_aij = aj / aij;
                double cicj = cicj_cache[ijp];
                double fac = cicj * ckcl / (aij*akl*sqrt(aij+akl));
                __syncthreads();
                if (sq_id == 0) {
                    aij_cache[0] = aij;
                    aij_cache[1] = aj_aij;
                    aij_cache[2] = ai * 2;
                }
                double xpa = rjri[0] * aj_aij;
                double ypa = rjri[1] * aj_aij;
                double zpa = rjri[2] * aj_aij;
                double xij = ri[0] + xpa;
                double yij = ri[1] + ypa;
                double zij = ri[2] + zpa;
                double xqc = xlxk * al_akl;
                double yqc = ylyk * al_akl;
                double zqc = zlzk * al_akl;
                double xkl = env[rk+0] + xqc;
                double ykl = env[rk+1] + yqc;
                double zkl = env[rk+2] + zqc;
                double xpq = xij - xkl;
                double ypq = yij - ykl;
                double zpq = zij - zkl;
                double theta = aij * akl / (aij + akl);
                double rr = xpq * xpq + ypq * ypq + zpq * zpq;
                int nroots = bounds.nroots;
                rys_roots_rs(nroots, theta, rr, jk.omega, rw, nsq_per_block, 0, 1);
                if (task_id >= ntasks) {
                    continue;
                }
                for (int irys = 0; irys < nroots; ++irys) {
                    double wt = rw[(2*irys+1)*nsq_per_block] * fac;
                    double rt = rw[ 2*irys   *nsq_per_block];
                    double aij = aij_cache[0];
                    double rt_aa = rt / (aij + akl);
                    double fx, fy, fz;
                    double rt_aij = rt_aa * akl;
                    double b10 = .5/aij * (1 - rt_aij);
                    double c0x = rjri[0] * aij_cache[1] - xpq*rt_aij;
                    double trr_10x = c0x * 1;
                    double trr_20x = c0x * trr_10x + 1*b10 * 1;
                    double hrr_1100x = trr_20x - rjri[0] * trr_10x;
                    fx = aij_cache[2] * hrr_1100x;
                    double c0y = rjri[1] * aij_cache[1] - ypq*rt_aij;
                    double trr_10y = c0y * 1;
                    fy = aij_cache[2] * trr_10y;
                    double c0z = rjri[2] * aij_cache[1] - zpq*rt_aij;
                    double trr_10z = c0z * wt;
                    fz = aij_cache[2] * trr_10z;
                    double hrr_0100x = trr_10x - rjri[0] * 1;
                    goutx[0] +=  fx  * 1 * wt;
                    gouty[0] += hrr_0100x *  fy  * wt;
                    goutz[0] += hrr_0100x * 1 *  fz ;
                    fx = aij_cache[2] * trr_10x;
                    double trr_20y = c0y * trr_10y + 1*b10 * 1;
                    double hrr_1100y = trr_20y - rjri[1] * trr_10y;
                    fy = aij_cache[2] * hrr_1100y;
                    fz = aij_cache[2] * trr_10z;
                    double hrr_0100y = trr_10y - rjri[1] * 1;
                    goutx[1] +=  fx  * hrr_0100y * wt;
                    gouty[1] += 1 *  fy  * wt;
                    goutz[1] += 1 * hrr_0100y *  fz ;
                    fx = aij_cache[2] * trr_10x;
                    fy = aij_cache[2] * trr_10y;
                    double trr_20z = c0z * trr_10z + 1*b10 * wt;
                    double hrr_1100z = trr_20z - rjri[2] * trr_10z;
                    fz = aij_cache[2] * hrr_1100z;
                    double hrr_0100z = trr_10z - rjri[2] * wt;
                    goutx[2] +=  fx  * 1 * hrr_0100z;
                    gouty[2] += 1 *  fy  * hrr_0100z;
                    goutz[2] += 1 * 1 *  fz ;
                }
            }
        }
        if (task_id < ntasks) {
            int *ao_loc = envs.ao_loc;
            int nao = ao_loc[nbas];
            int i0 = ao_loc[ish];
            int j0 = ao_loc[jsh];
            int k0 = ao_loc[ksh];
            int l0 = ao_loc[lsh];
            int ia = bas[ish*BAS_SLOTS+ATOM_OF] - jk.atom_offset;
            double *dm = jk.dm;
            int do_j = jk.vj != NULL;
            int do_k = jk.vk != NULL;
            double *vj_x = jk.vj + (ia*3+0)*(size_t)nao*nao;
            double *vj_y = jk.vj + (ia*3+1)*(size_t)nao*nao;
            double *vj_z = jk.vj + (ia*3+2)*(size_t)nao*nao;
            double *vk_x = jk.vk + (ia*3+0)*(size_t)nao*nao;
            double *vk_y = jk.vk + (ia*3+1)*(size_t)nao*nao;
            double *vk_z = jk.vk + (ia*3+2)*(size_t)nao*nao;
            if (do_j) {
                double dm_lk_00 = dm[(l0+0)*nao+(k0+0)];
                double vxij_00 = goutx[0]*dm_lk_00;
                atomicAdd(vj_x+(i0+0)*nao+(j0+0), vxij_00);
                double vyij_00 = gouty[0]*dm_lk_00;
                atomicAdd(vj_y+(i0+0)*nao+(j0+0), vyij_00);
                double vzij_00 = goutz[0]*dm_lk_00;
                atomicAdd(vj_z+(i0+0)*nao+(j0+0), vzij_00);
                double vxij_01 = goutx[1]*dm_lk_00;
                atomicAdd(vj_x+(i0+0)*nao+(j0+1), vxij_01);
                double vyij_01 = gouty[1]*dm_lk_00;
                atomicAdd(vj_y+(i0+0)*nao+(j0+1), vyij_01);
                double vzij_01 = goutz[1]*dm_lk_00;
                atomicAdd(vj_z+(i0+0)*nao+(j0+1), vzij_01);
                double vxij_02 = goutx[2]*dm_lk_00;
                atomicAdd(vj_x+(i0+0)*nao+(j0+2), vxij_02);
                double vyij_02 = gouty[2]*dm_lk_00;
                atomicAdd(vj_y+(i0+0)*nao+(j0+2), vyij_02);
                double vzij_02 = goutz[2]*dm_lk_00;
                atomicAdd(vj_z+(i0+0)*nao+(j0+2), vzij_02);
                double dm_ji_00 = dm[(j0+0)*nao+(i0+0)];
                double dm_ji_10 = dm[(j0+1)*nao+(i0+0)];
                double dm_ji_20 = dm[(j0+2)*nao+(i0+0)];
                double vxkl_00 = goutx[0]*dm_ji_00 + goutx[1]*dm_ji_10 + goutx[2]*dm_ji_20;
                atomicAdd(vj_x+(k0+0)*nao+(l0+0), vxkl_00);
                double vykl_00 = gouty[0]*dm_ji_00 + gouty[1]*dm_ji_10 + gouty[2]*dm_ji_20;
                atomicAdd(vj_y+(k0+0)*nao+(l0+0), vykl_00);
                double vzkl_00 = goutz[0]*dm_ji_00 + goutz[1]*dm_ji_10 + goutz[2]*dm_ji_20;
                atomicAdd(vj_z+(k0+0)*nao+(l0+0), vzkl_00);
            }
            if (do_k) {
                double dm_jk_00 = dm[(j0+0)*nao+(k0+0)];
                double dm_jk_10 = dm[(j0+1)*nao+(k0+0)];
                double dm_jk_20 = dm[(j0+2)*nao+(k0+0)];
                double vxil_00 = goutx[0]*dm_jk_00 + goutx[1]*dm_jk_10 + goutx[2]*dm_jk_20;
                atomicAdd(vk_x+(i0+0)*nao+(l0+0), vxil_00);
                double vyil_00 = gouty[0]*dm_jk_00 + gouty[1]*dm_jk_10 + gouty[2]*dm_jk_20;
                atomicAdd(vk_y+(i0+0)*nao+(l0+0), vyil_00);
                double vzil_00 = goutz[0]*dm_jk_00 + goutz[1]*dm_jk_10 + goutz[2]*dm_jk_20;
                atomicAdd(vk_z+(i0+0)*nao+(l0+0), vzil_00);
                double dm_jl_00 = dm[(j0+0)*nao+(l0+0)];
                double dm_jl_10 = dm[(j0+1)*nao+(l0+0)];
                double dm_jl_20 = dm[(j0+2)*nao+(l0+0)];
                double vxik_00 = goutx[0]*dm_jl_00 + goutx[1]*dm_jl_10 + goutx[2]*dm_jl_20;
                atomicAdd(vk_x+(i0+0)*nao+(k0+0), vxik_00);
                double vyik_00 = gouty[0]*dm_jl_00 + gouty[1]*dm_jl_10 + gouty[2]*dm_jl_20;
                atomicAdd(vk_y+(i0+0)*nao+(k0+0), vyik_00);
                double vzik_00 = goutz[0]*dm_jl_00 + goutz[1]*dm_jl_10 + goutz[2]*dm_jl_20;
                atomicAdd(vk_z+(i0+0)*nao+(k0+0), vzik_00);
                double dm_ik_00 = dm[(i0+0)*nao+(k0+0)];
                double vxjl_00 = goutx[0]*dm_ik_00;
                atomicAdd(vk_x+(j0+0)*nao+(l0+0), vxjl_00);
                double vyjl_00 = gouty[0]*dm_ik_00;
                atomicAdd(vk_y+(j0+0)*nao+(l0+0), vyjl_00);
                double vzjl_00 = goutz[0]*dm_ik_00;
                atomicAdd(vk_z+(j0+0)*nao+(l0+0), vzjl_00);
                double vxjl_10 = goutx[1]*dm_ik_00;
                atomicAdd(vk_x+(j0+1)*nao+(l0+0), vxjl_10);
                double vyjl_10 = gouty[1]*dm_ik_00;
                atomicAdd(vk_y+(j0+1)*nao+(l0+0), vyjl_10);
                double vzjl_10 = goutz[1]*dm_ik_00;
                atomicAdd(vk_z+(j0+1)*nao+(l0+0), vzjl_10);
                double vxjl_20 = goutx[2]*dm_ik_00;
                atomicAdd(vk_x+(j0+2)*nao+(l0+0), vxjl_20);
                double vyjl_20 = gouty[2]*dm_ik_00;
                atomicAdd(vk_y+(j0+2)*nao+(l0+0), vyjl_20);
                double vzjl_20 = goutz[2]*dm_ik_00;
                atomicAdd(vk_z+(j0+2)*nao+(l0+0), vzjl_20);
                double dm_il_00 = dm[(i0+0)*nao+(l0+0)];
                double vxjk_00 = goutx[0]*dm_il_00;
                atomicAdd(vk_x+(j0+0)*nao+(k0+0), vxjk_00);
                double vyjk_00 = gouty[0]*dm_il_00;
                atomicAdd(vk_y+(j0+0)*nao+(k0+0), vyjk_00);
                double vzjk_00 = goutz[0]*dm_il_00;
                atomicAdd(vk_z+(j0+0)*nao+(k0+0), vzjk_00);
                double vxjk_10 = goutx[1]*dm_il_00;
                atomicAdd(vk_x+(j0+1)*nao+(k0+0), vxjk_10);
                double vyjk_10 = gouty[1]*dm_il_00;
                atomicAdd(vk_y+(j0+1)*nao+(k0+0), vyjk_10);
                double vzjk_10 = goutz[1]*dm_il_00;
                atomicAdd(vk_z+(j0+1)*nao+(k0+0), vzjk_10);
                double vxjk_20 = goutx[2]*dm_il_00;
                atomicAdd(vk_x+(j0+2)*nao+(k0+0), vxjk_20);
                double vyjk_20 = gouty[2]*dm_il_00;
                atomicAdd(vk_y+(j0+2)*nao+(k0+0), vyjk_20);
                double vzjk_20 = goutz[2]*dm_il_00;
                atomicAdd(vk_z+(j0+2)*nao+(k0+0), vzjk_20);
            }
        }
    }
}
}

__global__ static
void rys_vjk_ip1_0110(RysIntEnvVars envs, JKMatrix jk, BoundsInfo bounds,
                    float *q_cond_ij, float *q_cond_kl, float dm_penalty,
                    float *s_cond_ij, float *s_cond_kl, float *diffuse_exps,
                    uint32_t *pool, int *head)
{
    int sq_id = threadIdx.x;
    int nbas = envs.nbas;
    int *bas = envs.bas;
    double *env = envs.env;
    int nroots = bounds.nroots;
    int nsq_per_block = blockDim.x;
    int gout_stride = blockDim.y;
    extern __shared__ double shared_memory[];
    double *rw = shared_memory + sq_id;
    double *cicj_cache = shared_memory + nsq_per_block * (nroots*2);
    int t_id = threadIdx.y * nsq_per_block + threadIdx.x;
    int threads = nsq_per_block * gout_stride;

    uint32_t *bas_kl_idx = pool + blockIdx.x * QUEUE_DEPTH;
    __shared__ int ntasks, pair_ij, pair_kl0;
while (1) {
    __syncthreads();
    __shared__ int ish, jsh;
    if (sq_id == 0) {
        int task_id = atomicAdd(head, 1);
        int batch_kl = task_id / bounds.npairs_ij;
        pair_ij = task_id - bounds.npairs_ij * batch_kl;
        pair_kl0 = batch_kl * (QUEUE_DEPTH - 512);
        uint32_t bas_ij = bounds.pair_ij_mapping[pair_ij];
        ish = bas_ij / nbas;
        jsh = bas_ij % nbas;
    }
    __syncthreads();
    if (pair_kl0 >= bounds.npairs_kl) {
        break;
    }
    if (jk.lr_factor != 0) {
        _fill_vjk_tasks_nosym(ntasks, pair_kl0, bas_kl_idx, pair_ij, ish, jsh,
                              q_cond_ij, q_cond_kl, dm_penalty, envs, bounds);
    } else {
        _fill_sr_vjk_tasks_nosym(ntasks, pair_kl0, bas_kl_idx, pair_ij, ish, jsh,
                                 q_cond_ij, q_cond_kl, dm_penalty,
                                 s_cond_ij, s_cond_kl, diffuse_exps, envs, bounds);
    }
    if (ntasks == 0) {
        continue;
    }
    __shared__ double ri[3];
    __shared__ double rjri[3];
    __shared__ double aij_cache[3];
    __shared__ int expi;
    __shared__ int expj;
    if (t_id == 0) {
        expi = bas[ish*BAS_SLOTS+PTR_EXP];
        expj = bas[jsh*BAS_SLOTS+PTR_EXP];
    }
    __syncthreads();
    if (t_id < 3) {
        int ri_ptr = bas[ish*BAS_SLOTS+PTR_BAS_COORD];
        int rj_ptr = bas[jsh*BAS_SLOTS+PTR_BAS_COORD];
        ri[t_id] = env[ri_ptr+t_id];
        rjri[t_id] = env[rj_ptr+t_id] - ri[t_id];
    }
    __syncthreads();
    double *ci = env + bas[ish*BAS_SLOTS+PTR_COEFF];
    double *cj = env + bas[jsh*BAS_SLOTS+PTR_COEFF];
    double xjxi = rjri[0];
    double yjyi = rjri[1];
    double zjzi = rjri[2];
    int iprim = bounds.iprim;
    int jprim = bounds.jprim;
    for (int ij = t_id; ij < iprim*jprim; ij += threads) {
        int ip = ij / jprim;
        int jp = ij % jprim;
        double ai = env[expi+ip];
        double aj = env[expj+jp];
        double aij = ai + aj;
        double theta_ij = ai * aj / aij;
        double rr_ij = xjxi*xjxi + yjyi*yjyi + zjzi*zjzi;
        double Kab = exp(-theta_ij * rr_ij);
        cicj_cache[ij] = ci[ip] * cj[jp] * Kab;
    }
    __syncthreads();
    for (int task_id = sq_id; task_id < ntasks+sq_id; task_id += nsq_per_block) {
        int iprim = bounds.iprim;
        int jprim = bounds.jprim;
        int kprim = bounds.kprim;
        int lprim = bounds.lprim;
        uint32_t bas_kl = bas_kl_idx[task_id];
        int ksh = bas_kl / nbas;
        int lsh = bas_kl % nbas;
        int expk = bas[ksh*BAS_SLOTS+PTR_EXP];
        int expl = bas[lsh*BAS_SLOTS+PTR_EXP];
        int ck = bas[ksh*BAS_SLOTS+PTR_COEFF];
        int cl = bas[lsh*BAS_SLOTS+PTR_COEFF];
        int rk = bas[ksh*BAS_SLOTS+PTR_BAS_COORD];
        int rl = bas[lsh*BAS_SLOTS+PTR_BAS_COORD];
        double xlxk = env[rl+0] - env[rk+0];
        double ylyk = env[rl+1] - env[rk+1];
        double zlzk = env[rl+2] - env[rk+2];
        double goutx[9];
        double gouty[9];
        double goutz[9];
        #pragma unroll
        for (int n = 0; n < 9; ++n) {
            goutx[n] = 0;
            gouty[n] = 0;
            goutz[n] = 0;
        }
        for (int klp = 0; klp < kprim*lprim; ++klp) {
            int kp = klp / lprim;
            int lp = klp % lprim;
            double ak = env[expk+kp];
            double al = env[expl+lp];
            double akl = ak + al;
            double al_akl = al / akl;
            double theta_kl = ak * al_akl;
            double fac_sym = PI_FAC;
            if (task_id < ntasks) {
                if (ksh == lsh) fac_sym *= .5;
            } else {
                fac_sym = 0;
            }
            double Kcd = exp(-theta_kl * (xlxk*xlxk+ylyk*ylyk+zlzk*zlzk));
            double ckcl = fac_sym * env[ck+kp] * env[cl+lp] * Kcd;
            for (int ijp = 0; ijp < iprim*jprim; ++ijp) {
                int ip = ijp / jprim;
                int jp = ijp % jprim;
                double ai = env[expi+ip];
                double aj = env[expj+jp];
                double aij = ai + aj;
                double aj_aij = aj / aij;
                double cicj = cicj_cache[ijp];
                double fac = cicj * ckcl / (aij*akl*sqrt(aij+akl));
                __syncthreads();
                if (sq_id == 0) {
                    aij_cache[0] = aij;
                    aij_cache[1] = aj_aij;
                    aij_cache[2] = ai * 2;
                }
                double xpa = rjri[0] * aj_aij;
                double ypa = rjri[1] * aj_aij;
                double zpa = rjri[2] * aj_aij;
                double xij = ri[0] + xpa;
                double yij = ri[1] + ypa;
                double zij = ri[2] + zpa;
                double xqc = xlxk * al_akl;
                double yqc = ylyk * al_akl;
                double zqc = zlzk * al_akl;
                double xkl = env[rk+0] + xqc;
                double ykl = env[rk+1] + yqc;
                double zkl = env[rk+2] + zqc;
                double xpq = xij - xkl;
                double ypq = yij - ykl;
                double zpq = zij - zkl;
                double theta = aij * akl / (aij + akl);
                double rr = xpq * xpq + ypq * ypq + zpq * zpq;
                int nroots = bounds.nroots;
                rys_roots_rs(nroots, theta, rr, jk.omega, rw, nsq_per_block, 0, 1);
                if (task_id >= ntasks) {
                    continue;
                }
                for (int irys = 0; irys < nroots; ++irys) {
                    double wt = rw[(2*irys+1)*nsq_per_block] * fac;
                    double rt = rw[ 2*irys   *nsq_per_block];
                    double aij = aij_cache[0];
                    double rt_aa = rt / (aij + akl);
                    double b00 = .5 * rt_aa;
                    double fx, fy, fz;
                    double rt_akl = rt_aa * aij;
                    double cpx = xqc + xpq*rt_akl;
                    double rt_aij = rt_aa * akl;
                    double b10 = .5/aij * (1 - rt_aij);
                    double c0x = rjri[0] * aij_cache[1] - xpq*rt_aij;
                    double trr_10x = c0x * 1;
                    double trr_20x = c0x * trr_10x + 1*b10 * 1;
                    double trr_21x = cpx * trr_20x + 2*b00 * trr_10x;
                    double trr_11x = cpx * trr_10x + 1*b00 * 1;
                    double hrr_1110x = trr_21x - rjri[0] * trr_11x;
                    fx = aij_cache[2] * hrr_1110x;
                    double c0y = rjri[1] * aij_cache[1] - ypq*rt_aij;
                    double trr_10y = c0y * 1;
                    fy = aij_cache[2] * trr_10y;
                    double c0z = rjri[2] * aij_cache[1] - zpq*rt_aij;
                    double trr_10z = c0z * wt;
                    fz = aij_cache[2] * trr_10z;
                    double trr_01x = cpx * 1;
                    double hrr_0110x = trr_11x - rjri[0] * trr_01x;
                    goutx[0] +=  fx  * 1 * wt;
                    gouty[0] += hrr_0110x *  fy  * wt;
                    goutz[0] += hrr_0110x * 1 *  fz ;
                    fx = aij_cache[2] * trr_11x;
                    double trr_20y = c0y * trr_10y + 1*b10 * 1;
                    double hrr_1100y = trr_20y - rjri[1] * trr_10y;
                    fy = aij_cache[2] * hrr_1100y;
                    fz = aij_cache[2] * trr_10z;
                    double hrr_0100y = trr_10y - rjri[1] * 1;
                    goutx[1] +=  fx  * hrr_0100y * wt;
                    gouty[1] += trr_01x *  fy  * wt;
                    goutz[1] += trr_01x * hrr_0100y *  fz ;
                    fx = aij_cache[2] * trr_11x;
                    fy = aij_cache[2] * trr_10y;
                    double trr_20z = c0z * trr_10z + 1*b10 * wt;
                    double hrr_1100z = trr_20z - rjri[2] * trr_10z;
                    fz = aij_cache[2] * hrr_1100z;
                    double hrr_0100z = trr_10z - rjri[2] * wt;
                    goutx[2] +=  fx  * 1 * hrr_0100z;
                    gouty[2] += trr_01x *  fy  * hrr_0100z;
                    goutz[2] += trr_01x * 1 *  fz ;
                    double hrr_1100x = trr_20x - rjri[0] * trr_10x;
                    fx = aij_cache[2] * hrr_1100x;
                    double cpy = yqc + ypq*rt_akl;
                    double trr_11y = cpy * trr_10y + 1*b00 * 1;
                    fy = aij_cache[2] * trr_11y;
                    fz = aij_cache[2] * trr_10z;
                    double hrr_0100x = trr_10x - rjri[0] * 1;
                    double trr_01y = cpy * 1;
                    goutx[3] +=  fx  * trr_01y * wt;
                    gouty[3] += hrr_0100x *  fy  * wt;
                    goutz[3] += hrr_0100x * trr_01y *  fz ;
                    fx = aij_cache[2] * trr_10x;
                    double trr_21y = cpy * trr_20y + 2*b00 * trr_10y;
                    double hrr_1110y = trr_21y - rjri[1] * trr_11y;
                    fy = aij_cache[2] * hrr_1110y;
                    fz = aij_cache[2] * trr_10z;
                    double hrr_0110y = trr_11y - rjri[1] * trr_01y;
                    goutx[4] +=  fx  * hrr_0110y * wt;
                    gouty[4] += 1 *  fy  * wt;
                    goutz[4] += 1 * hrr_0110y *  fz ;
                    fx = aij_cache[2] * trr_10x;
                    fy = aij_cache[2] * trr_11y;
                    fz = aij_cache[2] * hrr_1100z;
                    goutx[5] +=  fx  * trr_01y * hrr_0100z;
                    gouty[5] += 1 *  fy  * hrr_0100z;
                    goutz[5] += 1 * trr_01y *  fz ;
                    fx = aij_cache[2] * hrr_1100x;
                    fy = aij_cache[2] * trr_10y;
                    double cpz = zqc + zpq*rt_akl;
                    double trr_11z = cpz * trr_10z + 1*b00 * wt;
                    fz = aij_cache[2] * trr_11z;
                    double trr_01z = cpz * wt;
                    goutx[6] +=  fx  * 1 * trr_01z;
                    gouty[6] += hrr_0100x *  fy  * trr_01z;
                    goutz[6] += hrr_0100x * 1 *  fz ;
                    fx = aij_cache[2] * trr_10x;
                    fy = aij_cache[2] * hrr_1100y;
                    fz = aij_cache[2] * trr_11z;
                    goutx[7] +=  fx  * hrr_0100y * trr_01z;
                    gouty[7] += 1 *  fy  * trr_01z;
                    goutz[7] += 1 * hrr_0100y *  fz ;
                    fx = aij_cache[2] * trr_10x;
                    fy = aij_cache[2] * trr_10y;
                    double trr_21z = cpz * trr_20z + 2*b00 * trr_10z;
                    double hrr_1110z = trr_21z - rjri[2] * trr_11z;
                    fz = aij_cache[2] * hrr_1110z;
                    double hrr_0110z = trr_11z - rjri[2] * trr_01z;
                    goutx[8] +=  fx  * 1 * hrr_0110z;
                    gouty[8] += 1 *  fy  * hrr_0110z;
                    goutz[8] += 1 * 1 *  fz ;
                }
            }
        }
        if (task_id < ntasks) {
            int *ao_loc = envs.ao_loc;
            int nao = ao_loc[nbas];
            int i0 = ao_loc[ish];
            int j0 = ao_loc[jsh];
            int k0 = ao_loc[ksh];
            int l0 = ao_loc[lsh];
            int ia = bas[ish*BAS_SLOTS+ATOM_OF] - jk.atom_offset;
            double *dm = jk.dm;
            int do_j = jk.vj != NULL;
            int do_k = jk.vk != NULL;
            double *vj_x = jk.vj + (ia*3+0)*(size_t)nao*nao;
            double *vj_y = jk.vj + (ia*3+1)*(size_t)nao*nao;
            double *vj_z = jk.vj + (ia*3+2)*(size_t)nao*nao;
            double *vk_x = jk.vk + (ia*3+0)*(size_t)nao*nao;
            double *vk_y = jk.vk + (ia*3+1)*(size_t)nao*nao;
            double *vk_z = jk.vk + (ia*3+2)*(size_t)nao*nao;
            if (do_j) {
                double dm_lk_00 = dm[(l0+0)*nao+(k0+0)];
                double dm_lk_01 = dm[(l0+0)*nao+(k0+1)];
                double dm_lk_02 = dm[(l0+0)*nao+(k0+2)];
                double vxij_00 = goutx[0]*dm_lk_00 + goutx[3]*dm_lk_01 + goutx[6]*dm_lk_02;
                atomicAdd(vj_x+(i0+0)*nao+(j0+0), vxij_00);
                double vyij_00 = gouty[0]*dm_lk_00 + gouty[3]*dm_lk_01 + gouty[6]*dm_lk_02;
                atomicAdd(vj_y+(i0+0)*nao+(j0+0), vyij_00);
                double vzij_00 = goutz[0]*dm_lk_00 + goutz[3]*dm_lk_01 + goutz[6]*dm_lk_02;
                atomicAdd(vj_z+(i0+0)*nao+(j0+0), vzij_00);
                double vxij_01 = goutx[1]*dm_lk_00 + goutx[4]*dm_lk_01 + goutx[7]*dm_lk_02;
                atomicAdd(vj_x+(i0+0)*nao+(j0+1), vxij_01);
                double vyij_01 = gouty[1]*dm_lk_00 + gouty[4]*dm_lk_01 + gouty[7]*dm_lk_02;
                atomicAdd(vj_y+(i0+0)*nao+(j0+1), vyij_01);
                double vzij_01 = goutz[1]*dm_lk_00 + goutz[4]*dm_lk_01 + goutz[7]*dm_lk_02;
                atomicAdd(vj_z+(i0+0)*nao+(j0+1), vzij_01);
                double vxij_02 = goutx[2]*dm_lk_00 + goutx[5]*dm_lk_01 + goutx[8]*dm_lk_02;
                atomicAdd(vj_x+(i0+0)*nao+(j0+2), vxij_02);
                double vyij_02 = gouty[2]*dm_lk_00 + gouty[5]*dm_lk_01 + gouty[8]*dm_lk_02;
                atomicAdd(vj_y+(i0+0)*nao+(j0+2), vyij_02);
                double vzij_02 = goutz[2]*dm_lk_00 + goutz[5]*dm_lk_01 + goutz[8]*dm_lk_02;
                atomicAdd(vj_z+(i0+0)*nao+(j0+2), vzij_02);
                double dm_ji_00 = dm[(j0+0)*nao+(i0+0)];
                double dm_ji_10 = dm[(j0+1)*nao+(i0+0)];
                double dm_ji_20 = dm[(j0+2)*nao+(i0+0)];
                double vxkl_00 = goutx[0]*dm_ji_00 + goutx[1]*dm_ji_10 + goutx[2]*dm_ji_20;
                atomicAdd(vj_x+(k0+0)*nao+(l0+0), vxkl_00);
                double vykl_00 = gouty[0]*dm_ji_00 + gouty[1]*dm_ji_10 + gouty[2]*dm_ji_20;
                atomicAdd(vj_y+(k0+0)*nao+(l0+0), vykl_00);
                double vzkl_00 = goutz[0]*dm_ji_00 + goutz[1]*dm_ji_10 + goutz[2]*dm_ji_20;
                atomicAdd(vj_z+(k0+0)*nao+(l0+0), vzkl_00);
                double vxkl_10 = goutx[3]*dm_ji_00 + goutx[4]*dm_ji_10 + goutx[5]*dm_ji_20;
                atomicAdd(vj_x+(k0+1)*nao+(l0+0), vxkl_10);
                double vykl_10 = gouty[3]*dm_ji_00 + gouty[4]*dm_ji_10 + gouty[5]*dm_ji_20;
                atomicAdd(vj_y+(k0+1)*nao+(l0+0), vykl_10);
                double vzkl_10 = goutz[3]*dm_ji_00 + goutz[4]*dm_ji_10 + goutz[5]*dm_ji_20;
                atomicAdd(vj_z+(k0+1)*nao+(l0+0), vzkl_10);
                double vxkl_20 = goutx[6]*dm_ji_00 + goutx[7]*dm_ji_10 + goutx[8]*dm_ji_20;
                atomicAdd(vj_x+(k0+2)*nao+(l0+0), vxkl_20);
                double vykl_20 = gouty[6]*dm_ji_00 + gouty[7]*dm_ji_10 + gouty[8]*dm_ji_20;
                atomicAdd(vj_y+(k0+2)*nao+(l0+0), vykl_20);
                double vzkl_20 = goutz[6]*dm_ji_00 + goutz[7]*dm_ji_10 + goutz[8]*dm_ji_20;
                atomicAdd(vj_z+(k0+2)*nao+(l0+0), vzkl_20);
            }
            if (do_k) {
                double vxil_00 = 0;
                double vyil_00 = 0;
                double vzil_00 = 0;
                double dm_jk_00 = dm[(j0+0)*nao+(k0+0)];
                vxil_00 += goutx[0] * dm_jk_00;
                vyil_00 += gouty[0] * dm_jk_00;
                vzil_00 += goutz[0] * dm_jk_00;
                double dm_jk_01 = dm[(j0+0)*nao+(k0+1)];
                vxil_00 += goutx[3] * dm_jk_01;
                vyil_00 += gouty[3] * dm_jk_01;
                vzil_00 += goutz[3] * dm_jk_01;
                double dm_jk_02 = dm[(j0+0)*nao+(k0+2)];
                vxil_00 += goutx[6] * dm_jk_02;
                vyil_00 += gouty[6] * dm_jk_02;
                vzil_00 += goutz[6] * dm_jk_02;
                double dm_jk_10 = dm[(j0+1)*nao+(k0+0)];
                vxil_00 += goutx[1] * dm_jk_10;
                vyil_00 += gouty[1] * dm_jk_10;
                vzil_00 += goutz[1] * dm_jk_10;
                double dm_jk_11 = dm[(j0+1)*nao+(k0+1)];
                vxil_00 += goutx[4] * dm_jk_11;
                vyil_00 += gouty[4] * dm_jk_11;
                vzil_00 += goutz[4] * dm_jk_11;
                double dm_jk_12 = dm[(j0+1)*nao+(k0+2)];
                vxil_00 += goutx[7] * dm_jk_12;
                vyil_00 += gouty[7] * dm_jk_12;
                vzil_00 += goutz[7] * dm_jk_12;
                double dm_jk_20 = dm[(j0+2)*nao+(k0+0)];
                vxil_00 += goutx[2] * dm_jk_20;
                vyil_00 += gouty[2] * dm_jk_20;
                vzil_00 += goutz[2] * dm_jk_20;
                double dm_jk_21 = dm[(j0+2)*nao+(k0+1)];
                vxil_00 += goutx[5] * dm_jk_21;
                vyil_00 += gouty[5] * dm_jk_21;
                vzil_00 += goutz[5] * dm_jk_21;
                double dm_jk_22 = dm[(j0+2)*nao+(k0+2)];
                vxil_00 += goutx[8] * dm_jk_22;
                vyil_00 += gouty[8] * dm_jk_22;
                vzil_00 += goutz[8] * dm_jk_22;
                atomicAdd(vk_x+(i0+0)*nao+(l0+0), vxil_00);
                atomicAdd(vk_y+(i0+0)*nao+(l0+0), vyil_00);
                atomicAdd(vk_z+(i0+0)*nao+(l0+0), vzil_00);
                double dm_jl_00 = dm[(j0+0)*nao+(l0+0)];
                double dm_jl_10 = dm[(j0+1)*nao+(l0+0)];
                double dm_jl_20 = dm[(j0+2)*nao+(l0+0)];
                double vxik_00 = goutx[0]*dm_jl_00 + goutx[1]*dm_jl_10 + goutx[2]*dm_jl_20;
                atomicAdd(vk_x+(i0+0)*nao+(k0+0), vxik_00);
                double vyik_00 = gouty[0]*dm_jl_00 + gouty[1]*dm_jl_10 + gouty[2]*dm_jl_20;
                atomicAdd(vk_y+(i0+0)*nao+(k0+0), vyik_00);
                double vzik_00 = goutz[0]*dm_jl_00 + goutz[1]*dm_jl_10 + goutz[2]*dm_jl_20;
                atomicAdd(vk_z+(i0+0)*nao+(k0+0), vzik_00);
                double vxik_01 = goutx[3]*dm_jl_00 + goutx[4]*dm_jl_10 + goutx[5]*dm_jl_20;
                atomicAdd(vk_x+(i0+0)*nao+(k0+1), vxik_01);
                double vyik_01 = gouty[3]*dm_jl_00 + gouty[4]*dm_jl_10 + gouty[5]*dm_jl_20;
                atomicAdd(vk_y+(i0+0)*nao+(k0+1), vyik_01);
                double vzik_01 = goutz[3]*dm_jl_00 + goutz[4]*dm_jl_10 + goutz[5]*dm_jl_20;
                atomicAdd(vk_z+(i0+0)*nao+(k0+1), vzik_01);
                double vxik_02 = goutx[6]*dm_jl_00 + goutx[7]*dm_jl_10 + goutx[8]*dm_jl_20;
                atomicAdd(vk_x+(i0+0)*nao+(k0+2), vxik_02);
                double vyik_02 = gouty[6]*dm_jl_00 + gouty[7]*dm_jl_10 + gouty[8]*dm_jl_20;
                atomicAdd(vk_y+(i0+0)*nao+(k0+2), vyik_02);
                double vzik_02 = goutz[6]*dm_jl_00 + goutz[7]*dm_jl_10 + goutz[8]*dm_jl_20;
                atomicAdd(vk_z+(i0+0)*nao+(k0+2), vzik_02);
                double dm_ik_00 = dm[(i0+0)*nao+(k0+0)];
                double dm_ik_01 = dm[(i0+0)*nao+(k0+1)];
                double dm_ik_02 = dm[(i0+0)*nao+(k0+2)];
                double vxjl_00 = goutx[0]*dm_ik_00 + goutx[3]*dm_ik_01 + goutx[6]*dm_ik_02;
                atomicAdd(vk_x+(j0+0)*nao+(l0+0), vxjl_00);
                double vyjl_00 = gouty[0]*dm_ik_00 + gouty[3]*dm_ik_01 + gouty[6]*dm_ik_02;
                atomicAdd(vk_y+(j0+0)*nao+(l0+0), vyjl_00);
                double vzjl_00 = goutz[0]*dm_ik_00 + goutz[3]*dm_ik_01 + goutz[6]*dm_ik_02;
                atomicAdd(vk_z+(j0+0)*nao+(l0+0), vzjl_00);
                double vxjl_10 = goutx[1]*dm_ik_00 + goutx[4]*dm_ik_01 + goutx[7]*dm_ik_02;
                atomicAdd(vk_x+(j0+1)*nao+(l0+0), vxjl_10);
                double vyjl_10 = gouty[1]*dm_ik_00 + gouty[4]*dm_ik_01 + gouty[7]*dm_ik_02;
                atomicAdd(vk_y+(j0+1)*nao+(l0+0), vyjl_10);
                double vzjl_10 = goutz[1]*dm_ik_00 + goutz[4]*dm_ik_01 + goutz[7]*dm_ik_02;
                atomicAdd(vk_z+(j0+1)*nao+(l0+0), vzjl_10);
                double vxjl_20 = goutx[2]*dm_ik_00 + goutx[5]*dm_ik_01 + goutx[8]*dm_ik_02;
                atomicAdd(vk_x+(j0+2)*nao+(l0+0), vxjl_20);
                double vyjl_20 = gouty[2]*dm_ik_00 + gouty[5]*dm_ik_01 + gouty[8]*dm_ik_02;
                atomicAdd(vk_y+(j0+2)*nao+(l0+0), vyjl_20);
                double vzjl_20 = goutz[2]*dm_ik_00 + goutz[5]*dm_ik_01 + goutz[8]*dm_ik_02;
                atomicAdd(vk_z+(j0+2)*nao+(l0+0), vzjl_20);
                double dm_il_00 = dm[(i0+0)*nao+(l0+0)];
                double vxjk_00 = goutx[0]*dm_il_00;
                atomicAdd(vk_x+(j0+0)*nao+(k0+0), vxjk_00);
                double vyjk_00 = gouty[0]*dm_il_00;
                atomicAdd(vk_y+(j0+0)*nao+(k0+0), vyjk_00);
                double vzjk_00 = goutz[0]*dm_il_00;
                atomicAdd(vk_z+(j0+0)*nao+(k0+0), vzjk_00);
                double vxjk_01 = goutx[3]*dm_il_00;
                atomicAdd(vk_x+(j0+0)*nao+(k0+1), vxjk_01);
                double vyjk_01 = gouty[3]*dm_il_00;
                atomicAdd(vk_y+(j0+0)*nao+(k0+1), vyjk_01);
                double vzjk_01 = goutz[3]*dm_il_00;
                atomicAdd(vk_z+(j0+0)*nao+(k0+1), vzjk_01);
                double vxjk_02 = goutx[6]*dm_il_00;
                atomicAdd(vk_x+(j0+0)*nao+(k0+2), vxjk_02);
                double vyjk_02 = gouty[6]*dm_il_00;
                atomicAdd(vk_y+(j0+0)*nao+(k0+2), vyjk_02);
                double vzjk_02 = goutz[6]*dm_il_00;
                atomicAdd(vk_z+(j0+0)*nao+(k0+2), vzjk_02);
                double vxjk_10 = goutx[1]*dm_il_00;
                atomicAdd(vk_x+(j0+1)*nao+(k0+0), vxjk_10);
                double vyjk_10 = gouty[1]*dm_il_00;
                atomicAdd(vk_y+(j0+1)*nao+(k0+0), vyjk_10);
                double vzjk_10 = goutz[1]*dm_il_00;
                atomicAdd(vk_z+(j0+1)*nao+(k0+0), vzjk_10);
                double vxjk_11 = goutx[4]*dm_il_00;
                atomicAdd(vk_x+(j0+1)*nao+(k0+1), vxjk_11);
                double vyjk_11 = gouty[4]*dm_il_00;
                atomicAdd(vk_y+(j0+1)*nao+(k0+1), vyjk_11);
                double vzjk_11 = goutz[4]*dm_il_00;
                atomicAdd(vk_z+(j0+1)*nao+(k0+1), vzjk_11);
                double vxjk_12 = goutx[7]*dm_il_00;
                atomicAdd(vk_x+(j0+1)*nao+(k0+2), vxjk_12);
                double vyjk_12 = gouty[7]*dm_il_00;
                atomicAdd(vk_y+(j0+1)*nao+(k0+2), vyjk_12);
                double vzjk_12 = goutz[7]*dm_il_00;
                atomicAdd(vk_z+(j0+1)*nao+(k0+2), vzjk_12);
                double vxjk_20 = goutx[2]*dm_il_00;
                atomicAdd(vk_x+(j0+2)*nao+(k0+0), vxjk_20);
                double vyjk_20 = gouty[2]*dm_il_00;
                atomicAdd(vk_y+(j0+2)*nao+(k0+0), vyjk_20);
                double vzjk_20 = goutz[2]*dm_il_00;
                atomicAdd(vk_z+(j0+2)*nao+(k0+0), vzjk_20);
                double vxjk_21 = goutx[5]*dm_il_00;
                atomicAdd(vk_x+(j0+2)*nao+(k0+1), vxjk_21);
                double vyjk_21 = gouty[5]*dm_il_00;
                atomicAdd(vk_y+(j0+2)*nao+(k0+1), vyjk_21);
                double vzjk_21 = goutz[5]*dm_il_00;
                atomicAdd(vk_z+(j0+2)*nao+(k0+1), vzjk_21);
                double vxjk_22 = goutx[8]*dm_il_00;
                atomicAdd(vk_x+(j0+2)*nao+(k0+2), vxjk_22);
                double vyjk_22 = gouty[8]*dm_il_00;
                atomicAdd(vk_y+(j0+2)*nao+(k0+2), vyjk_22);
                double vzjk_22 = goutz[8]*dm_il_00;
                atomicAdd(vk_z+(j0+2)*nao+(k0+2), vzjk_22);
            }
        }
    }
}
}

__global__ static
void rys_vjk_ip1_0111(RysIntEnvVars envs, JKMatrix jk, BoundsInfo bounds,
                    float *q_cond_ij, float *q_cond_kl, float dm_penalty,
                    float *s_cond_ij, float *s_cond_kl, float *diffuse_exps,
                    uint32_t *pool, int *head)
{
    int sq_id = threadIdx.x;
    int nbas = envs.nbas;
    int *bas = envs.bas;
    double *env = envs.env;
    int nroots = bounds.nroots;
    int nsq_per_block = blockDim.x;
    int gout_stride = blockDim.y;
    extern __shared__ double shared_memory[];
    double *rw = shared_memory + sq_id;
    double *cicj_cache = shared_memory + nsq_per_block * (nroots*2);
    int t_id = threadIdx.y * nsq_per_block + threadIdx.x;
    int threads = nsq_per_block * gout_stride;

    uint32_t *bas_kl_idx = pool + blockIdx.x * QUEUE_DEPTH;
    __shared__ int ntasks, pair_ij, pair_kl0;
while (1) {
    __syncthreads();
    __shared__ int ish, jsh;
    if (sq_id == 0) {
        int task_id = atomicAdd(head, 1);
        int batch_kl = task_id / bounds.npairs_ij;
        pair_ij = task_id - bounds.npairs_ij * batch_kl;
        pair_kl0 = batch_kl * (QUEUE_DEPTH - 512);
        uint32_t bas_ij = bounds.pair_ij_mapping[pair_ij];
        ish = bas_ij / nbas;
        jsh = bas_ij % nbas;
    }
    __syncthreads();
    if (pair_kl0 >= bounds.npairs_kl) {
        break;
    }
    if (jk.lr_factor != 0) {
        _fill_vjk_tasks_nosym(ntasks, pair_kl0, bas_kl_idx, pair_ij, ish, jsh,
                              q_cond_ij, q_cond_kl, dm_penalty, envs, bounds);
    } else {
        _fill_sr_vjk_tasks_nosym(ntasks, pair_kl0, bas_kl_idx, pair_ij, ish, jsh,
                                 q_cond_ij, q_cond_kl, dm_penalty,
                                 s_cond_ij, s_cond_kl, diffuse_exps, envs, bounds);
    }
    if (ntasks == 0) {
        continue;
    }
    __shared__ double ri[3];
    __shared__ double rjri[3];
    __shared__ double aij_cache[3];
    __shared__ int expi;
    __shared__ int expj;
    if (t_id == 0) {
        expi = bas[ish*BAS_SLOTS+PTR_EXP];
        expj = bas[jsh*BAS_SLOTS+PTR_EXP];
    }
    __syncthreads();
    if (t_id < 3) {
        int ri_ptr = bas[ish*BAS_SLOTS+PTR_BAS_COORD];
        int rj_ptr = bas[jsh*BAS_SLOTS+PTR_BAS_COORD];
        ri[t_id] = env[ri_ptr+t_id];
        rjri[t_id] = env[rj_ptr+t_id] - ri[t_id];
    }
    __syncthreads();
    double *ci = env + bas[ish*BAS_SLOTS+PTR_COEFF];
    double *cj = env + bas[jsh*BAS_SLOTS+PTR_COEFF];
    double xjxi = rjri[0];
    double yjyi = rjri[1];
    double zjzi = rjri[2];
    int iprim = bounds.iprim;
    int jprim = bounds.jprim;
    for (int ij = t_id; ij < iprim*jprim; ij += threads) {
        int ip = ij / jprim;
        int jp = ij % jprim;
        double ai = env[expi+ip];
        double aj = env[expj+jp];
        double aij = ai + aj;
        double theta_ij = ai * aj / aij;
        double rr_ij = xjxi*xjxi + yjyi*yjyi + zjzi*zjzi;
        double Kab = exp(-theta_ij * rr_ij);
        cicj_cache[ij] = ci[ip] * cj[jp] * Kab;
    }
    __syncthreads();
    for (int task_id = sq_id; task_id < ntasks+sq_id; task_id += nsq_per_block) {
        int iprim = bounds.iprim;
        int jprim = bounds.jprim;
        int kprim = bounds.kprim;
        int lprim = bounds.lprim;
        uint32_t bas_kl = bas_kl_idx[task_id];
        int ksh = bas_kl / nbas;
        int lsh = bas_kl % nbas;
        int expk = bas[ksh*BAS_SLOTS+PTR_EXP];
        int expl = bas[lsh*BAS_SLOTS+PTR_EXP];
        int ck = bas[ksh*BAS_SLOTS+PTR_COEFF];
        int cl = bas[lsh*BAS_SLOTS+PTR_COEFF];
        int rk = bas[ksh*BAS_SLOTS+PTR_BAS_COORD];
        int rl = bas[lsh*BAS_SLOTS+PTR_BAS_COORD];
        double xlxk = env[rl+0] - env[rk+0];
        double ylyk = env[rl+1] - env[rk+1];
        double zlzk = env[rl+2] - env[rk+2];
        double goutx[27];
        double gouty[27];
        double goutz[27];
        #pragma unroll
        for (int n = 0; n < 27; ++n) {
            goutx[n] = 0;
            gouty[n] = 0;
            goutz[n] = 0;
        }
        for (int klp = 0; klp < kprim*lprim; ++klp) {
            int kp = klp / lprim;
            int lp = klp % lprim;
            double ak = env[expk+kp];
            double al = env[expl+lp];
            double akl = ak + al;
            double al_akl = al / akl;
            double theta_kl = ak * al_akl;
            double fac_sym = PI_FAC;
            if (task_id < ntasks) {
                if (ksh == lsh) fac_sym *= .5;
            } else {
                fac_sym = 0;
            }
            double Kcd = exp(-theta_kl * (xlxk*xlxk+ylyk*ylyk+zlzk*zlzk));
            double ckcl = fac_sym * env[ck+kp] * env[cl+lp] * Kcd;
            for (int ijp = 0; ijp < iprim*jprim; ++ijp) {
                int ip = ijp / jprim;
                int jp = ijp % jprim;
                double ai = env[expi+ip];
                double aj = env[expj+jp];
                double aij = ai + aj;
                double aj_aij = aj / aij;
                double cicj = cicj_cache[ijp];
                double fac = cicj * ckcl / (aij*akl*sqrt(aij+akl));
                __syncthreads();
                if (sq_id == 0) {
                    aij_cache[0] = aij;
                    aij_cache[1] = aj_aij;
                    aij_cache[2] = ai * 2;
                }
                double xpa = rjri[0] * aj_aij;
                double ypa = rjri[1] * aj_aij;
                double zpa = rjri[2] * aj_aij;
                double xij = ri[0] + xpa;
                double yij = ri[1] + ypa;
                double zij = ri[2] + zpa;
                double xqc = xlxk * al_akl;
                double yqc = ylyk * al_akl;
                double zqc = zlzk * al_akl;
                double xkl = env[rk+0] + xqc;
                double ykl = env[rk+1] + yqc;
                double zkl = env[rk+2] + zqc;
                double xpq = xij - xkl;
                double ypq = yij - ykl;
                double zpq = zij - zkl;
                double theta = aij * akl / (aij + akl);
                double rr = xpq * xpq + ypq * ypq + zpq * zpq;
                int nroots = bounds.nroots;
                rys_roots_rs(nroots, theta, rr, jk.omega, rw, nsq_per_block, 0, 1);
                if (task_id >= ntasks) {
                    continue;
                }
                for (int irys = 0; irys < nroots; ++irys) {
                    double wt = rw[(2*irys+1)*nsq_per_block] * fac;
                    double rt = rw[ 2*irys   *nsq_per_block];
                    double aij = aij_cache[0];
                    double rt_aa = rt / (aij + akl);
                    double b00 = .5 * rt_aa;
                    double fx, fy, fz;
                    double rt_akl = rt_aa * aij;
                    double b01 = .5/akl * (1 - rt_akl);
                    double cpx = xqc + xpq*rt_akl;
                    double rt_aij = rt_aa * akl;
                    double b10 = .5/aij * (1 - rt_aij);
                    double c0x = rjri[0] * aij_cache[1] - xpq*rt_aij;
                    double trr_10x = c0x * 1;
                    double trr_20x = c0x * trr_10x + 1*b10 * 1;
