                    float *s_cond_ij, float *s_cond_kl, float *diffuse_exps,
                    uint32_t *pool, int *head)
{
    int sq_id = threadIdx.x;
    int nbas = envs.nbas;
    int *bas = envs.bas;
    double *env = envs.env;
    int nroots = bounds.nroots;
    int gout_id = threadIdx.y;
    constexpr int nsq_per_block = 64;
    constexpr int gout_stride = 4;
    extern __shared__ double shared_memory[];
    double *rlrk = shared_memory + sq_id;
    double *Rpq = shared_memory + nsq_per_block * 3 + sq_id;
    double *akl_cache = shared_memory + nsq_per_block * 6 + sq_id;
    double *gx = shared_memory + nsq_per_block * 8 + sq_id;
    double *rw = shared_memory + nsq_per_block * 62 + sq_id;
    double *cicj_cache = shared_memory + nsq_per_block * (62+nroots*2);
    int t_id = threadIdx.y * nsq_per_block + threadIdx.x;
    int threads = nsq_per_block * gout_stride;

    uint32_t *bas_kl_idx = pool + blockIdx.x * QUEUE_DEPTH;
    __shared__ int ntasks, pair_ij, pair_kl0;
while (1) {
    __syncthreads();
    __shared__ int ish, jsh;
    if (sq_id == 0) {
        int task_id = atomicAdd(head, 1);
        int batch_kl = task_id / bounds.npairs_ij;
        pair_ij = task_id - bounds.npairs_ij * batch_kl;
        pair_kl0 = batch_kl * (QUEUE_DEPTH - 512);
        uint32_t bas_ij = bounds.pair_ij_mapping[pair_ij];
        ish = bas_ij / nbas;
        jsh = bas_ij % nbas;
    }
    __syncthreads();
    if (pair_kl0 >= bounds.npairs_kl) {
        break;
    }
    if (jk.lr_factor != 0) {
        _fill_vjk_tasks_nosym(ntasks, pair_kl0, bas_kl_idx, pair_ij, ish, jsh,
                              q_cond_ij, q_cond_kl, dm_penalty, envs, bounds);
    } else {
        _fill_sr_vjk_tasks_nosym(ntasks, pair_kl0, bas_kl_idx, pair_ij, ish, jsh,
                                 q_cond_ij, q_cond_kl, dm_penalty,
                                 s_cond_ij, s_cond_kl, diffuse_exps, envs, bounds);
    }
    if (ntasks == 0) {
        continue;
    }
    __shared__ double ri[3];
    __shared__ double rjri[3];
    __shared__ double aij_cache[3];
    __shared__ int expi;
    __shared__ int expj;
    if (t_id == 0) {
        expi = bas[ish*BAS_SLOTS+PTR_EXP];
        expj = bas[jsh*BAS_SLOTS+PTR_EXP];
    }
    __syncthreads();
    if (t_id < 3) {
        int ri_ptr = bas[ish*BAS_SLOTS+PTR_BAS_COORD];
        int rj_ptr = bas[jsh*BAS_SLOTS+PTR_BAS_COORD];
        ri[t_id] = env[ri_ptr+t_id];
        rjri[t_id] = env[rj_ptr+t_id] - ri[t_id];
    }
    __syncthreads();
    double *ci = env + bas[ish*BAS_SLOTS+PTR_COEFF];
    double *cj = env + bas[jsh*BAS_SLOTS+PTR_COEFF];
    double xjxi = rjri[0];
    double yjyi = rjri[1];
    double zjzi = rjri[2];
    int iprim = bounds.iprim;
    int jprim = bounds.jprim;
    for (int ij = t_id; ij < iprim*jprim; ij += threads) {
        int ip = ij / jprim;
        int jp = ij % jprim;
        double ai = env[expi+ip];
        double aj = env[expj+jp];
        double aij = ai + aj;
        double theta_ij = ai * aj / aij;
        double rr_ij = xjxi*xjxi + yjyi*yjyi + zjzi*zjzi;
        double Kab = exp(-theta_ij * rr_ij);
        cicj_cache[ij] = ci[ip] * cj[jp] * Kab;
    }
    __syncthreads();
    for (int task_id = sq_id; task_id < ntasks+sq_id; task_id += nsq_per_block) {
        int iprim = bounds.iprim;
        int jprim = bounds.jprim;
        int kprim = bounds.kprim;
        int lprim = bounds.lprim;
        uint32_t bas_kl = bas_kl_idx[task_id];
        int ksh = bas_kl / nbas;
        int lsh = bas_kl % nbas;
        int expk = bas[ksh*BAS_SLOTS+PTR_EXP];
        int expl = bas[lsh*BAS_SLOTS+PTR_EXP];
        int ck = bas[ksh*BAS_SLOTS+PTR_COEFF];
        int cl = bas[lsh*BAS_SLOTS+PTR_COEFF];
        int rk = bas[ksh*BAS_SLOTS+PTR_BAS_COORD];
        int rl = bas[lsh*BAS_SLOTS+PTR_BAS_COORD];
        double xlxk = env[rl+0] - env[rk+0];
        double ylyk = env[rl+1] - env[rk+1];
        double zlzk = env[rl+2] - env[rk+2];
        if (gout_id == 0) {
            rlrk[0] = xlxk;
            rlrk[64] = ylyk;
            rlrk[128] = zlzk;
        }
        double goutx[9];
        double gouty[9];
        double goutz[9];
        #pragma unroll
        for (int n = 0; n < 9; ++n) {
            goutx[n] = 0;
            gouty[n] = 0;
            goutz[n] = 0;
        }
        for (int klp = 0; klp < kprim*lprim; ++klp) {
            int kp = klp / lprim;
            int lp = klp % lprim;
            double ak = env[expk+kp];
            double al = env[expl+lp];
            double akl = ak + al;
            double al_akl = al / akl;
            double theta_kl = ak * al_akl;
            double fac_sym = PI_FAC;
            if (task_id < ntasks) {
                if (ksh == lsh) fac_sym *= .5;
            } else {
                fac_sym = 0;
            }
            __syncthreads();
            if (gout_id == 0) {
                double xlxk = rlrk[0];
                double ylyk = rlrk[64];
                double zlzk = rlrk[128];
                double Kcd = exp(-theta_kl * (xlxk*xlxk+ylyk*ylyk+zlzk*zlzk));
                double ckcl = env[ck+kp] * env[cl+lp] * Kcd;
                gx[0] = fac_sym * ckcl;
                akl_cache[0] = akl;
                akl_cache[nsq_per_block] = al_akl;
            }
            for (int ijp = 0; ijp < iprim*jprim; ++ijp) {
                int ip = ijp / jprim;
                int jp = ijp % jprim;
                double ai = env[expi+ip];
                double aj = env[expj+jp];
                double aij = ai + aj;
                double aj_aij = aj / aij;
                double xpa = rjri[0] * aj_aij;
                double ypa = rjri[1] * aj_aij;
                double zpa = rjri[2] * aj_aij;
                double xij = ri[0] + xpa;
                double yij = ri[1] + ypa;
                double zij = ri[2] + zpa;
                double xkl = env[rk+0] + rlrk[0] * al_akl;
                double ykl = env[rk+1] + rlrk[64] * al_akl;
                double zkl = env[rk+2] + rlrk[128] * al_akl;
                double xpq = xij - xkl;
                double ypq = yij - ykl;
                double zpq = zij - zkl;
                double theta = aij * akl / (aij + akl);
                double rr = xpq * xpq + ypq * ypq + zpq * zpq;
                __syncthreads();
                if (gout_id == 0) {
                    Rpq[0] = xpq;
                    Rpq[64] = ypq;
                    Rpq[128] = zpq;
                    double cicj = cicj_cache[ijp];
                    gx[1152] = cicj / (aij*akl*sqrt(aij+akl));
                    if (sq_id == 0) {
                        aij_cache[0] = aij;
                        aij_cache[1] = aj_aij;
                        aij_cache[2] = ai * 2;
                    }
                }
                int nroots = bounds.nroots;
                rys_roots_rs(nroots, theta, rr, jk.omega, rw, nsq_per_block, gout_id, gout_stride);
                double s0, s1, s2;
                double Ix, Iy, Iz;
                for (int irys = 0; irys < nroots; ++irys) {
                    __syncthreads();
                    double rt = rw[irys*128];
                    double aij = aij_cache[0];
                    double akl = akl_cache[0];
                    double rt_aa = rt / (aij + akl);
                    double rt_aij = rt_aa * akl;
                    double b10 = .5/aij * (1 - rt_aij);
                    double rt_akl = rt_aa * aij;
                    double b00 = .5 * rt_aa;
                    double b01 = .5/akl * (1 - rt_akl);
                    for (int n = gout_id; n < 3; n += 4) {
                        if (n == 2) {
                            gx[2304] = rw[irys*128+64];
                        }
                        double *_gx = gx + n * 1152;
                        double xjxi = rjri[n];
                        double Rpa = xjxi * aij_cache[1];
                        double c0x = Rpa - rt_aij * Rpq[n*64];
                        s0 = _gx[0];
                        s1 = c0x * s0;
                        _gx[64] = s1;
                        s2 = c0x * s1 + 1 * b10 * s0;
                        _gx[128] = s2;
                        s0 = s1;
                        s1 = s2;
                        s2 = c0x * s1 + 2 * b10 * s0;
                        _gx[192] = s2;
                        double xlxk = rlrk[n*64];
                        double Rqc = xlxk * akl_cache[64];
                        double cpx = Rqc + rt_akl * Rpq[n*64];
                        s0 = _gx[0];
                        s1 = cpx * s0;
                        _gx[384] = s1;
                        s2 = cpx*s1 + 1 * b01 *s0;
                        _gx[768] = s2;
                        s0 = _gx[64];
                        s1 = cpx * s0;
                        s1 += 1 * b00 * _gx[0];
                        _gx[448] = s1;
                        s2 = cpx*s1 + 1 * b01 *s0;
                        s2 += 1 * b00 * _gx[384];
                        _gx[832] = s2;
                        s0 = _gx[128];
                        s1 = cpx * s0;
                        s1 += 2 * b00 * _gx[64];
                        _gx[512] = s1;
                        s2 = cpx*s1 + 1 * b01 *s0;
                        s2 += 2 * b00 * _gx[448];
                        _gx[896] = s2;
                        s0 = _gx[192];
                        s1 = cpx * s0;
                        s1 += 3 * b00 * _gx[128];
                        _gx[576] = s1;
                        s2 = cpx*s1 + 1 * b01 *s0;
                        s2 += 3 * b00 * _gx[512];
                        _gx[960] = s2;
                        s1 = _gx[192];
                        s0 = _gx[128];
                        _gx[256] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[64];
                        _gx[192] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[0];
                        _gx[128] = s1 - xjxi * s0;
                        s1 = _gx[256];
                        s0 = _gx[192];
                        _gx[320] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[128];
                        _gx[256] = s1 - xjxi * s0;
                        s1 = _gx[576];
                        s0 = _gx[512];
                        _gx[640] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[448];
                        _gx[576] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[384];
                        _gx[512] = s1 - xjxi * s0;
                        s1 = _gx[640];
                        s0 = _gx[576];
                        _gx[704] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[512];
                        _gx[640] = s1 - xjxi * s0;
                        s1 = _gx[960];
                        s0 = _gx[896];
                        _gx[1024] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[832];
                        _gx[960] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[768];
                        _gx[896] = s1 - xjxi * s0;
                        s1 = _gx[1024];
                        s0 = _gx[960];
                        _gx[1088] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[896];
                        _gx[1024] = s1 - xjxi * s0;
                    }
                    __syncthreads();
                    switch (gout_id) {
                    case 0:
                    Ix = gx[1024];
                    Iy = gx[1152];
                    Iz = gx[2304];
                    goutx[0] += aij_cache[2] * gx[1088] * Iy * Iz;
                    gouty[0] += aij_cache[2] * gx[1216] * Ix * Iz;
                    goutz[0] += aij_cache[2] * gx[2368] * Ix * Iy;
                    Ix = gx[768];
                    Iy = gx[1280];
                    Iz = gx[2432];
                    goutx[1] += aij_cache[2] * gx[832] * Iy * Iz;
                    gouty[1] += aij_cache[2] * gx[1344] * Ix * Iz;
                    goutz[1] += aij_cache[2] * gx[2496] * Ix * Iy;
                    Ix = gx[512];
                    Iy = gx[1536];
                    Iz = gx[2432];
                    goutx[2] += aij_cache[2] * gx[576] * Iy * Iz;
                    gouty[2] += aij_cache[2] * gx[1600] * Ix * Iz;
                    goutz[2] += aij_cache[2] * gx[2496] * Ix * Iy;
                    Ix = gx[640];
                    Iy = gx[1152];
                    Iz = gx[2688];
                    goutx[3] += aij_cache[2] * gx[704] * Iy * Iz;
                    gouty[3] += aij_cache[2] * gx[1216] * Ix * Iz;
                    goutz[3] += aij_cache[2] * gx[2752] * Ix * Iy;
                    Ix = gx[384];
                    Iy = gx[1280];
                    Iz = gx[2816];
                    goutx[4] += aij_cache[2] * gx[448] * Iy * Iz;
                    gouty[4] += aij_cache[2] * gx[1344] * Ix * Iz;
                    goutz[4] += aij_cache[2] * gx[2880] * Ix * Iy;
                    Ix = gx[128];
                    Iy = gx[1920];
                    Iz = gx[2432];
                    goutx[5] += aij_cache[2] * gx[192] * Iy * Iz;
                    gouty[5] += aij_cache[2] * gx[1984] * Ix * Iz;
                    goutz[5] += aij_cache[2] * gx[2496] * Ix * Iy;
                    Ix = gx[256];
                    Iy = gx[1536];
                    Iz = gx[2688];
                    goutx[6] += aij_cache[2] * gx[320] * Iy * Iz;
                    gouty[6] += aij_cache[2] * gx[1600] * Ix * Iz;
                    goutz[6] += aij_cache[2] * gx[2752] * Ix * Iy;
                    Ix = gx[0];
                    Iy = gx[1664];
                    Iz = gx[2816];
                    goutx[7] += aij_cache[2] * gx[64] * Iy * Iz;
                    gouty[7] += aij_cache[2] * gx[1728] * Ix * Iz;
                    goutz[7] += aij_cache[2] * gx[2880] * Ix * Iy;
                    Ix = gx[128];
                    Iy = gx[1152];
                    Iz = gx[3200];
                    goutx[8] += aij_cache[2] * gx[192] * Iy * Iz;
                    gouty[8] += aij_cache[2] * gx[1216] * Ix * Iz;
                    goutz[8] += aij_cache[2] * gx[3264] * Ix * Iy;
                    break;
                    case 1:
                    Ix = gx[896];
                    Iy = gx[1280];
                    Iz = gx[2304];
                    goutx[0] += aij_cache[2] * gx[960] * Iy * Iz;
                    gouty[0] += aij_cache[2] * gx[1344] * Ix * Iz;
                    goutz[0] += aij_cache[2] * gx[2368] * Ix * Iy;
                    Ix = gx[768];
                    Iy = gx[1152];
                    Iz = gx[2560];
                    goutx[1] += aij_cache[2] * gx[832] * Iy * Iz;
                    gouty[1] += aij_cache[2] * gx[1216] * Ix * Iz;
                    goutz[1] += aij_cache[2] * gx[2624] * Ix * Iy;
                    Ix = gx[384];
                    Iy = gx[1792];
                    Iz = gx[2304];
                    goutx[2] += aij_cache[2] * gx[448] * Iy * Iz;
                    gouty[2] += aij_cache[2] * gx[1856] * Ix * Iz;
                    goutz[2] += aij_cache[2] * gx[2368] * Ix * Iy;
                    Ix = gx[512];
                    Iy = gx[1280];
                    Iz = gx[2688];
                    goutx[3] += aij_cache[2] * gx[576] * Iy * Iz;
                    gouty[3] += aij_cache[2] * gx[1344] * Ix * Iz;
                    goutz[3] += aij_cache[2] * gx[2752] * Ix * Iy;
                    Ix = gx[384];
                    Iy = gx[1152];
                    Iz = gx[2944];
                    goutx[4] += aij_cache[2] * gx[448] * Iy * Iz;
                    gouty[4] += aij_cache[2] * gx[1216] * Ix * Iz;
                    goutz[4] += aij_cache[2] * gx[3008] * Ix * Iy;
                    Ix = gx[0];
                    Iy = gx[2176];
                    Iz = gx[2304];
                    goutx[5] += aij_cache[2] * gx[64] * Iy * Iz;
                    gouty[5] += aij_cache[2] * gx[2240] * Ix * Iz;
                    goutz[5] += aij_cache[2] * gx[2368] * Ix * Iy;
                    Ix = gx[128];
                    Iy = gx[1664];
                    Iz = gx[2688];
                    goutx[6] += aij_cache[2] * gx[192] * Iy * Iz;
                    gouty[6] += aij_cache[2] * gx[1728] * Ix * Iz;
                    goutz[6] += aij_cache[2] * gx[2752] * Ix * Iy;
                    Ix = gx[0];
                    Iy = gx[1536];
                    Iz = gx[2944];
                    goutx[7] += aij_cache[2] * gx[64] * Iy * Iz;
                    gouty[7] += aij_cache[2] * gx[1600] * Ix * Iz;
                    goutz[7] += aij_cache[2] * gx[3008] * Ix * Iy;
                    Ix = gx[0];
                    Iy = gx[1408];
                    Iz = gx[3072];
                    goutx[8] += aij_cache[2] * gx[64] * Iy * Iz;
                    gouty[8] += aij_cache[2] * gx[1472] * Ix * Iz;
                    goutz[8] += aij_cache[2] * gx[3136] * Ix * Iy;
                    break;
