                    Ix = gx[0];
                    Iy = gx[2048];
                    Iz = gx[2432];
                    goutx[5] += aij_cache[2] * gx[64] * Iy * Iz;
                    gouty[5] += aij_cache[2] * gx[2112] * Ix * Iz;
                    goutz[5] += aij_cache[2] * gx[2496] * Ix * Iy;
                    Ix = gx[128];
                    Iy = gx[1536];
