    if (jk.lr_factor != 0) {
        _fill_vjk_tasks_nosym(ntasks, pair_kl0, bas_kl_idx, pair_ij, ish, jsh,
                              q_cond_ij, q_cond_kl, dm_penalty, envs, bounds);
    } else {
        _fill_sr_vjk_tasks_nosym(ntasks, pair_kl0, bas_kl_idx, pair_ij, ish, jsh,
                                 q_cond_ij, q_cond_kl, dm_penalty,
                                 s_cond_ij, s_cond_kl, diffuse_exps, envs, bounds);
    }
    if (ntasks == 0) {
        continue;
    }
    __shared__ double ri[3];
    __shared__ double rjri[3];
    __shared__ double aij_cache[3];
    __shared__ int expi;
    __shared__ int expj;
    if (t_id == 0) {
        expi = bas[ish*BAS_SLOTS+PTR_EXP];
        expj = bas[jsh*BAS_SLOTS+PTR_EXP];
    }
    __syncthreads();
    if (t_id < 3) {
        int ri_ptr = bas[ish*BAS_SLOTS+PTR_BAS_COORD];
        int rj_ptr = bas[jsh*BAS_SLOTS+PTR_BAS_COORD];
        ri[t_id] = env[ri_ptr+t_id];
        rjri[t_id] = env[rj_ptr+t_id] - ri[t_id];
    }
    __syncthreads();
    double *ci = env + bas[ish*BAS_SLOTS+PTR_COEFF];
    double *cj = env + bas[jsh*BAS_SLOTS+PTR_COEFF];
    double xjxi = rjri[0];
    double yjyi = rjri[1];
    double zjzi = rjri[2];
    int iprim = bounds.iprim;
    int jprim = bounds.jprim;
    for (int ij = t_id; ij < iprim*jprim; ij += threads) {
        int ip = ij / jprim;
        int jp = ij % jprim;
        double ai = env[expi+ip];
        double aj = env[expj+jp];
        double aij = ai + aj;
        double theta_ij = ai * aj / aij;
        double rr_ij = xjxi*xjxi + yjyi*yjyi + zjzi*zjzi;
        double Kab = exp(-theta_ij * rr_ij);
        cicj_cache[ij] = ci[ip] * cj[jp] * Kab;
    }
    __syncthreads();
    for (int task_id = sq_id; task_id < ntasks+sq_id; task_id += nsq_per_block) {
        int iprim = bounds.iprim;
        int jprim = bounds.jprim;
        int kprim = bounds.kprim;
        int lprim = bounds.lprim;
        uint32_t bas_kl = bas_kl_idx[task_id];
        int ksh = bas_kl / nbas;
        int lsh = bas_kl % nbas;
        int expk = bas[ksh*BAS_SLOTS+PTR_EXP];
        int expl = bas[lsh*BAS_SLOTS+PTR_EXP];
        int ck = bas[ksh*BAS_SLOTS+PTR_COEFF];
        int cl = bas[lsh*BAS_SLOTS+PTR_COEFF];
        int rk = bas[ksh*BAS_SLOTS+PTR_BAS_COORD];
        int rl = bas[lsh*BAS_SLOTS+PTR_BAS_COORD];
        double xlxk = env[rl+0] - env[rk+0];
        double ylyk = env[rl+1] - env[rk+1];
        double zlzk = env[rl+2] - env[rk+2];
        double goutx[9];
        double gouty[9];
        double goutz[9];
        #pragma unroll
        for (int n = 0; n < 9; ++n) {
            goutx[n] = 0;
            gouty[n] = 0;
            goutz[n] = 0;
        }
        for (int klp = 0; klp < kprim*lprim; ++klp) {
            int kp = klp / lprim;
            int lp = klp % lprim;
            double ak = env[expk+kp];
            double al = env[expl+lp];
            double akl = ak + al;
            double al_akl = al / akl;
            double theta_kl = ak * al_akl;
            double fac_sym = PI_FAC;
            if (task_id < ntasks) {
                if (ksh == lsh) fac_sym *= .5;
            } else {
                fac_sym = 0;
            }
            double Kcd = exp(-theta_kl * (xlxk*xlxk+ylyk*ylyk+zlzk*zlzk));
            double ckcl = fac_sym * env[ck+kp] * env[cl+lp] * Kcd;
            for (int ijp = 0; ijp < iprim*jprim; ++ijp) {
                int ip = ijp / jprim;
                int jp = ijp % jprim;
                double ai = env[expi+ip];
                double aj = env[expj+jp];
                double aij = ai + aj;
                double aj_aij = aj / aij;
                double cicj = cicj_cache[ijp];
                double fac = cicj * ckcl / (aij*akl*sqrt(aij+akl));
                __syncthreads();
                if (sq_id == 0) {
                    aij_cache[0] = aij;
                    aij_cache[1] = aj_aij;
                    aij_cache[2] = ai * 2;
                }
                double xpa = rjri[0] * aj_aij;
                double ypa = rjri[1] * aj_aij;
                double zpa = rjri[2] * aj_aij;
                double xij = ri[0] + xpa;
                double yij = ri[1] + ypa;
                double zij = ri[2] + zpa;
                double xqc = xlxk * al_akl;
                double yqc = ylyk * al_akl;
                double zqc = zlzk * al_akl;
                double xkl = env[rk+0] + xqc;
                double ykl = env[rk+1] + yqc;
                double zkl = env[rk+2] + zqc;
                double xpq = xij - xkl;
                double ypq = yij - ykl;
                double zpq = zij - zkl;
                double theta = aij * akl / (aij + akl);
                double rr = xpq * xpq + ypq * ypq + zpq * zpq;
                int nroots = bounds.nroots;
                rys_roots_rs(nroots, theta, rr, jk.omega, rw, nsq_per_block, 0, 1);
                if (task_id >= ntasks) {
                    continue;
                }
                for (int irys = 0; irys < nroots; ++irys) {
                    double wt = rw[(2*irys+1)*nsq_per_block] * fac;
                    double rt = rw[ 2*irys   *nsq_per_block];
                    double aij = aij_cache[0];
                    double rt_aa = rt / (aij + akl);
                    double b00 = .5 * rt_aa;
                    double fx, fy, fz;
                    double rt_akl = rt_aa * aij;
                    double cpx = xqc + xpq*rt_akl;
                    double rt_aij = rt_aa * akl;
                    double b10 = .5/aij * (1 - rt_aij);
                    double c0x = rjri[0] * aij_cache[1] - xpq*rt_aij;
                    double trr_10x = c0x * 1;
                    double trr_20x = c0x * trr_10x + 1*b10 * 1;
                    double trr_21x = cpx * trr_20x + 2*b00 * trr_10x;
                    fx = aij_cache[2] * trr_21x;
                    double c0y = rjri[1] * aij_cache[1] - ypq*rt_aij;
                    double trr_10y = c0y * 1;
                    fy = aij_cache[2] * trr_10y;
                    double c0z = rjri[2] * aij_cache[1] - zpq*rt_aij;
                    double trr_10z = c0z * wt;
                    fz = aij_cache[2] * trr_10z;
                    double trr_01x = cpx * 1;
                    fx -= 1 * trr_01x;
                    double trr_11x = cpx * trr_10x + 1*b00 * 1;
                    goutx[0] +=  fx  * 1 * wt;
                    gouty[0] += trr_11x *  fy  * wt;
                    goutz[0] += trr_11x * 1 *  fz ;
                    fx = aij_cache[2] * trr_11x;
                    double trr_20y = c0y * trr_10y + 1*b10 * 1;
                    fy = aij_cache[2] * trr_20y;
                    fz = aij_cache[2] * trr_10z;
                    fy -= 1 * 1;
                    goutx[1] +=  fx  * trr_10y * wt;
                    gouty[1] += trr_01x *  fy  * wt;
                    goutz[1] += trr_01x * trr_10y *  fz ;
                    fx = aij_cache[2] * trr_11x;
                    fy = aij_cache[2] * trr_10y;
                    double trr_20z = c0z * trr_10z + 1*b10 * wt;
                    fz = aij_cache[2] * trr_20z;
                    fz -= 1 * wt;
                    goutx[2] +=  fx  * 1 * trr_10z;
                    gouty[2] += trr_01x *  fy  * trr_10z;
                    goutz[2] += trr_01x * 1 *  fz ;
                    fx = aij_cache[2] * trr_20x;
                    double cpy = yqc + ypq*rt_akl;
                    double trr_11y = cpy * trr_10y + 1*b00 * 1;
                    fy = aij_cache[2] * trr_11y;
                    fz = aij_cache[2] * trr_10z;
                    fx -= 1 * 1;
                    double trr_01y = cpy * 1;
                    goutx[3] +=  fx  * trr_01y * wt;
                    gouty[3] += trr_10x *  fy  * wt;
                    goutz[3] += trr_10x * trr_01y *  fz ;
                    fx = aij_cache[2] * trr_10x;
                    double trr_21y = cpy * trr_20y + 2*b00 * trr_10y;
                    fy = aij_cache[2] * trr_21y;
                    fz = aij_cache[2] * trr_10z;
                    fy -= 1 * trr_01y;
                    goutx[4] +=  fx  * trr_11y * wt;
                    gouty[4] += 1 *  fy  * wt;
                    goutz[4] += 1 * trr_11y *  fz ;
                    fx = aij_cache[2] * trr_10x;
                    fy = aij_cache[2] * trr_11y;
                    fz = aij_cache[2] * trr_20z;
                    fz -= 1 * wt;
                    goutx[5] +=  fx  * trr_01y * trr_10z;
                    gouty[5] += 1 *  fy  * trr_10z;
                    goutz[5] += 1 * trr_01y *  fz ;
                    fx = aij_cache[2] * trr_20x;
                    fy = aij_cache[2] * trr_10y;
                    double cpz = zqc + zpq*rt_akl;
                    double trr_11z = cpz * trr_10z + 1*b00 * wt;
                    fz = aij_cache[2] * trr_11z;
                    fx -= 1 * 1;
                    double trr_01z = cpz * wt;
                    goutx[6] +=  fx  * 1 * trr_01z;
                    gouty[6] += trr_10x *  fy  * trr_01z;
                    goutz[6] += trr_10x * 1 *  fz ;
                    fx = aij_cache[2] * trr_10x;
                    fy = aij_cache[2] * trr_20y;
                    fz = aij_cache[2] * trr_11z;
                    fy -= 1 * 1;
                    goutx[7] +=  fx  * trr_10y * trr_01z;
                    gouty[7] += 1 *  fy  * trr_01z;
                    goutz[7] += 1 * trr_10y *  fz ;
                    fx = aij_cache[2] * trr_10x;
                    fy = aij_cache[2] * trr_10y;
                    double trr_21z = cpz * trr_20z + 2*b00 * trr_10z;
                    fz = aij_cache[2] * trr_21z;
                    fz -= 1 * trr_01z;
                    goutx[8] +=  fx  * 1 * trr_11z;
                    gouty[8] += 1 *  fy  * trr_11z;
                    goutz[8] += 1 * 1 *  fz ;
                }
            }
        }
        if (task_id < ntasks) {
            int *ao_loc = envs.ao_loc;
            int nao = ao_loc[nbas];
            int i0 = ao_loc[ish];
            int j0 = ao_loc[jsh];
            int k0 = ao_loc[ksh];
            int l0 = ao_loc[lsh];
            int ia = bas[ish*BAS_SLOTS+ATOM_OF] - jk.atom_offset;
            double *dm = jk.dm;
            int do_j = jk.vj != NULL;
            int do_k = jk.vk != NULL;
            double *vj_x = jk.vj + (ia*3+0)*(size_t)nao*nao;
            double *vj_y = jk.vj + (ia*3+1)*(size_t)nao*nao;
            double *vj_z = jk.vj + (ia*3+2)*(size_t)nao*nao;
            double *vk_x = jk.vk + (ia*3+0)*(size_t)nao*nao;
            double *vk_y = jk.vk + (ia*3+1)*(size_t)nao*nao;
            double *vk_z = jk.vk + (ia*3+2)*(size_t)nao*nao;
            if (do_j) {
                double dm_lk_00 = dm[(l0+0)*nao+(k0+0)];
                double dm_lk_01 = dm[(l0+0)*nao+(k0+1)];
                double dm_lk_02 = dm[(l0+0)*nao+(k0+2)];
                double vxij_00 = goutx[0]*dm_lk_00 + goutx[3]*dm_lk_01 + goutx[6]*dm_lk_02;
                atomicAdd(vj_x+(i0+0)*nao+(j0+0), vxij_00);
                double vyij_00 = gouty[0]*dm_lk_00 + gouty[3]*dm_lk_01 + gouty[6]*dm_lk_02;
                atomicAdd(vj_y+(i0+0)*nao+(j0+0), vyij_00);
                double vzij_00 = goutz[0]*dm_lk_00 + goutz[3]*dm_lk_01 + goutz[6]*dm_lk_02;
                atomicAdd(vj_z+(i0+0)*nao+(j0+0), vzij_00);
                double vxij_10 = goutx[1]*dm_lk_00 + goutx[4]*dm_lk_01 + goutx[7]*dm_lk_02;
                atomicAdd(vj_x+(i0+1)*nao+(j0+0), vxij_10);
                double vyij_10 = gouty[1]*dm_lk_00 + gouty[4]*dm_lk_01 + gouty[7]*dm_lk_02;
                atomicAdd(vj_y+(i0+1)*nao+(j0+0), vyij_10);
                double vzij_10 = goutz[1]*dm_lk_00 + goutz[4]*dm_lk_01 + goutz[7]*dm_lk_02;
                atomicAdd(vj_z+(i0+1)*nao+(j0+0), vzij_10);
                double vxij_20 = goutx[2]*dm_lk_00 + goutx[5]*dm_lk_01 + goutx[8]*dm_lk_02;
                atomicAdd(vj_x+(i0+2)*nao+(j0+0), vxij_20);
                double vyij_20 = gouty[2]*dm_lk_00 + gouty[5]*dm_lk_01 + gouty[8]*dm_lk_02;
                atomicAdd(vj_y+(i0+2)*nao+(j0+0), vyij_20);
                double vzij_20 = goutz[2]*dm_lk_00 + goutz[5]*dm_lk_01 + goutz[8]*dm_lk_02;
                atomicAdd(vj_z+(i0+2)*nao+(j0+0), vzij_20);
                double dm_ji_00 = dm[(j0+0)*nao+(i0+0)];
                double dm_ji_01 = dm[(j0+0)*nao+(i0+1)];
                double dm_ji_02 = dm[(j0+0)*nao+(i0+2)];
                double vxkl_00 = goutx[0]*dm_ji_00 + goutx[1]*dm_ji_01 + goutx[2]*dm_ji_02;
                atomicAdd(vj_x+(k0+0)*nao+(l0+0), vxkl_00);
                double vykl_00 = gouty[0]*dm_ji_00 + gouty[1]*dm_ji_01 + gouty[2]*dm_ji_02;
                atomicAdd(vj_y+(k0+0)*nao+(l0+0), vykl_00);
                double vzkl_00 = goutz[0]*dm_ji_00 + goutz[1]*dm_ji_01 + goutz[2]*dm_ji_02;
                atomicAdd(vj_z+(k0+0)*nao+(l0+0), vzkl_00);
                double vxkl_10 = goutx[3]*dm_ji_00 + goutx[4]*dm_ji_01 + goutx[5]*dm_ji_02;
                atomicAdd(vj_x+(k0+1)*nao+(l0+0), vxkl_10);
                double vykl_10 = gouty[3]*dm_ji_00 + gouty[4]*dm_ji_01 + gouty[5]*dm_ji_02;
                atomicAdd(vj_y+(k0+1)*nao+(l0+0), vykl_10);
                double vzkl_10 = goutz[3]*dm_ji_00 + goutz[4]*dm_ji_01 + goutz[5]*dm_ji_02;
                atomicAdd(vj_z+(k0+1)*nao+(l0+0), vzkl_10);
                double vxkl_20 = goutx[6]*dm_ji_00 + goutx[7]*dm_ji_01 + goutx[8]*dm_ji_02;
                atomicAdd(vj_x+(k0+2)*nao+(l0+0), vxkl_20);
                double vykl_20 = gouty[6]*dm_ji_00 + gouty[7]*dm_ji_01 + gouty[8]*dm_ji_02;
                atomicAdd(vj_y+(k0+2)*nao+(l0+0), vykl_20);
                double vzkl_20 = goutz[6]*dm_ji_00 + goutz[7]*dm_ji_01 + goutz[8]*dm_ji_02;
                atomicAdd(vj_z+(k0+2)*nao+(l0+0), vzkl_20);
            }
            if (do_k) {
                double dm_jk_00 = dm[(j0+0)*nao+(k0+0)];
                double dm_jk_01 = dm[(j0+0)*nao+(k0+1)];
                double dm_jk_02 = dm[(j0+0)*nao+(k0+2)];
                double vxil_00 = goutx[0]*dm_jk_00 + goutx[3]*dm_jk_01 + goutx[6]*dm_jk_02;
                atomicAdd(vk_x+(i0+0)*nao+(l0+0), vxil_00);
                double vyil_00 = gouty[0]*dm_jk_00 + gouty[3]*dm_jk_01 + gouty[6]*dm_jk_02;
                atomicAdd(vk_y+(i0+0)*nao+(l0+0), vyil_00);
                double vzil_00 = goutz[0]*dm_jk_00 + goutz[3]*dm_jk_01 + goutz[6]*dm_jk_02;
                atomicAdd(vk_z+(i0+0)*nao+(l0+0), vzil_00);
                double vxil_10 = goutx[1]*dm_jk_00 + goutx[4]*dm_jk_01 + goutx[7]*dm_jk_02;
                atomicAdd(vk_x+(i0+1)*nao+(l0+0), vxil_10);
                double vyil_10 = gouty[1]*dm_jk_00 + gouty[4]*dm_jk_01 + gouty[7]*dm_jk_02;
                atomicAdd(vk_y+(i0+1)*nao+(l0+0), vyil_10);
                double vzil_10 = goutz[1]*dm_jk_00 + goutz[4]*dm_jk_01 + goutz[7]*dm_jk_02;
                atomicAdd(vk_z+(i0+1)*nao+(l0+0), vzil_10);
                double vxil_20 = goutx[2]*dm_jk_00 + goutx[5]*dm_jk_01 + goutx[8]*dm_jk_02;
                atomicAdd(vk_x+(i0+2)*nao+(l0+0), vxil_20);
                double vyil_20 = gouty[2]*dm_jk_00 + gouty[5]*dm_jk_01 + gouty[8]*dm_jk_02;
                atomicAdd(vk_y+(i0+2)*nao+(l0+0), vyil_20);
                double vzil_20 = goutz[2]*dm_jk_00 + goutz[5]*dm_jk_01 + goutz[8]*dm_jk_02;
                atomicAdd(vk_z+(i0+2)*nao+(l0+0), vzil_20);
                double dm_jl_00 = dm[(j0+0)*nao+(l0+0)];
                double vxik_00 = goutx[0]*dm_jl_00;
                atomicAdd(vk_x+(i0+0)*nao+(k0+0), vxik_00);
                double vyik_00 = gouty[0]*dm_jl_00;
                atomicAdd(vk_y+(i0+0)*nao+(k0+0), vyik_00);
                double vzik_00 = goutz[0]*dm_jl_00;
                atomicAdd(vk_z+(i0+0)*nao+(k0+0), vzik_00);
                double vxik_01 = goutx[3]*dm_jl_00;
                atomicAdd(vk_x+(i0+0)*nao+(k0+1), vxik_01);
                double vyik_01 = gouty[3]*dm_jl_00;
                atomicAdd(vk_y+(i0+0)*nao+(k0+1), vyik_01);
                double vzik_01 = goutz[3]*dm_jl_00;
                atomicAdd(vk_z+(i0+0)*nao+(k0+1), vzik_01);
                double vxik_02 = goutx[6]*dm_jl_00;
                atomicAdd(vk_x+(i0+0)*nao+(k0+2), vxik_02);
                double vyik_02 = gouty[6]*dm_jl_00;
                atomicAdd(vk_y+(i0+0)*nao+(k0+2), vyik_02);
                double vzik_02 = goutz[6]*dm_jl_00;
                atomicAdd(vk_z+(i0+0)*nao+(k0+2), vzik_02);
                double vxik_10 = goutx[1]*dm_jl_00;
                atomicAdd(vk_x+(i0+1)*nao+(k0+0), vxik_10);
                double vyik_10 = gouty[1]*dm_jl_00;
                atomicAdd(vk_y+(i0+1)*nao+(k0+0), vyik_10);
                double vzik_10 = goutz[1]*dm_jl_00;
                atomicAdd(vk_z+(i0+1)*nao+(k0+0), vzik_10);
                double vxik_11 = goutx[4]*dm_jl_00;
                atomicAdd(vk_x+(i0+1)*nao+(k0+1), vxik_11);
                double vyik_11 = gouty[4]*dm_jl_00;
                atomicAdd(vk_y+(i0+1)*nao+(k0+1), vyik_11);
                double vzik_11 = goutz[4]*dm_jl_00;
                atomicAdd(vk_z+(i0+1)*nao+(k0+1), vzik_11);
                double vxik_12 = goutx[7]*dm_jl_00;
                atomicAdd(vk_x+(i0+1)*nao+(k0+2), vxik_12);
                double vyik_12 = gouty[7]*dm_jl_00;
                atomicAdd(vk_y+(i0+1)*nao+(k0+2), vyik_12);
                double vzik_12 = goutz[7]*dm_jl_00;
                atomicAdd(vk_z+(i0+1)*nao+(k0+2), vzik_12);
                double vxik_20 = goutx[2]*dm_jl_00;
                atomicAdd(vk_x+(i0+2)*nao+(k0+0), vxik_20);
                double vyik_20 = gouty[2]*dm_jl_00;
                atomicAdd(vk_y+(i0+2)*nao+(k0+0), vyik_20);
                double vzik_20 = goutz[2]*dm_jl_00;
                atomicAdd(vk_z+(i0+2)*nao+(k0+0), vzik_20);
                double vxik_21 = goutx[5]*dm_jl_00;
                atomicAdd(vk_x+(i0+2)*nao+(k0+1), vxik_21);
                double vyik_21 = gouty[5]*dm_jl_00;
                atomicAdd(vk_y+(i0+2)*nao+(k0+1), vyik_21);
                double vzik_21 = goutz[5]*dm_jl_00;
                atomicAdd(vk_z+(i0+2)*nao+(k0+1), vzik_21);
                double vxik_22 = goutx[8]*dm_jl_00;
                atomicAdd(vk_x+(i0+2)*nao+(k0+2), vxik_22);
                double vyik_22 = gouty[8]*dm_jl_00;
                atomicAdd(vk_y+(i0+2)*nao+(k0+2), vyik_22);
                double vzik_22 = goutz[8]*dm_jl_00;
                atomicAdd(vk_z+(i0+2)*nao+(k0+2), vzik_22);
                double vxjl_00 = 0;
                double vyjl_00 = 0;
                double vzjl_00 = 0;
                double dm_ik_00 = dm[(i0+0)*nao+(k0+0)];
                vxjl_00 += goutx[0] * dm_ik_00;
                vyjl_00 += gouty[0] * dm_ik_00;
                vzjl_00 += goutz[0] * dm_ik_00;
                double dm_ik_01 = dm[(i0+0)*nao+(k0+1)];
                vxjl_00 += goutx[3] * dm_ik_01;
                vyjl_00 += gouty[3] * dm_ik_01;
                vzjl_00 += goutz[3] * dm_ik_01;
                double dm_ik_02 = dm[(i0+0)*nao+(k0+2)];
                vxjl_00 += goutx[6] * dm_ik_02;
                vyjl_00 += gouty[6] * dm_ik_02;
                vzjl_00 += goutz[6] * dm_ik_02;
                double dm_ik_10 = dm[(i0+1)*nao+(k0+0)];
                vxjl_00 += goutx[1] * dm_ik_10;
                vyjl_00 += gouty[1] * dm_ik_10;
                vzjl_00 += goutz[1] * dm_ik_10;
                double dm_ik_11 = dm[(i0+1)*nao+(k0+1)];
                vxjl_00 += goutx[4] * dm_ik_11;
                vyjl_00 += gouty[4] * dm_ik_11;
                vzjl_00 += goutz[4] * dm_ik_11;
                double dm_ik_12 = dm[(i0+1)*nao+(k0+2)];
                vxjl_00 += goutx[7] * dm_ik_12;
                vyjl_00 += gouty[7] * dm_ik_12;
                vzjl_00 += goutz[7] * dm_ik_12;
                double dm_ik_20 = dm[(i0+2)*nao+(k0+0)];
                vxjl_00 += goutx[2] * dm_ik_20;
                vyjl_00 += gouty[2] * dm_ik_20;
                vzjl_00 += goutz[2] * dm_ik_20;
                double dm_ik_21 = dm[(i0+2)*nao+(k0+1)];
                vxjl_00 += goutx[5] * dm_ik_21;
                vyjl_00 += gouty[5] * dm_ik_21;
                vzjl_00 += goutz[5] * dm_ik_21;
                double dm_ik_22 = dm[(i0+2)*nao+(k0+2)];
                vxjl_00 += goutx[8] * dm_ik_22;
                vyjl_00 += gouty[8] * dm_ik_22;
                vzjl_00 += goutz[8] * dm_ik_22;
                atomicAdd(vk_x+(j0+0)*nao+(l0+0), vxjl_00);
                atomicAdd(vk_y+(j0+0)*nao+(l0+0), vyjl_00);
                atomicAdd(vk_z+(j0+0)*nao+(l0+0), vzjl_00);
                double dm_il_00 = dm[(i0+0)*nao+(l0+0)];
                double dm_il_10 = dm[(i0+1)*nao+(l0+0)];
                double dm_il_20 = dm[(i0+2)*nao+(l0+0)];
                double vxjk_00 = goutx[0]*dm_il_00 + goutx[1]*dm_il_10 + goutx[2]*dm_il_20;
                atomicAdd(vk_x+(j0+0)*nao+(k0+0), vxjk_00);
                double vyjk_00 = gouty[0]*dm_il_00 + gouty[1]*dm_il_10 + gouty[2]*dm_il_20;
                atomicAdd(vk_y+(j0+0)*nao+(k0+0), vyjk_00);
                double vzjk_00 = goutz[0]*dm_il_00 + goutz[1]*dm_il_10 + goutz[2]*dm_il_20;
                atomicAdd(vk_z+(j0+0)*nao+(k0+0), vzjk_00);
                double vxjk_01 = goutx[3]*dm_il_00 + goutx[4]*dm_il_10 + goutx[5]*dm_il_20;
                atomicAdd(vk_x+(j0+0)*nao+(k0+1), vxjk_01);
                double vyjk_01 = gouty[3]*dm_il_00 + gouty[4]*dm_il_10 + gouty[5]*dm_il_20;
                atomicAdd(vk_y+(j0+0)*nao+(k0+1), vyjk_01);
                double vzjk_01 = goutz[3]*dm_il_00 + goutz[4]*dm_il_10 + goutz[5]*dm_il_20;
                atomicAdd(vk_z+(j0+0)*nao+(k0+1), vzjk_01);
                double vxjk_02 = goutx[6]*dm_il_00 + goutx[7]*dm_il_10 + goutx[8]*dm_il_20;
                atomicAdd(vk_x+(j0+0)*nao+(k0+2), vxjk_02);
                double vyjk_02 = gouty[6]*dm_il_00 + gouty[7]*dm_il_10 + gouty[8]*dm_il_20;
                atomicAdd(vk_y+(j0+0)*nao+(k0+2), vyjk_02);
                double vzjk_02 = goutz[6]*dm_il_00 + goutz[7]*dm_il_10 + goutz[8]*dm_il_20;
                atomicAdd(vk_z+(j0+0)*nao+(k0+2), vzjk_02);
            }
        }
    }
}
}

__global__ static
void rys_vjk_ip1_1011(RysIntEnvVars envs, JKMatrix jk, BoundsInfo bounds,
                    float *q_cond_ij, float *q_cond_kl, float dm_penalty,
                    float *s_cond_ij, float *s_cond_kl, float *diffuse_exps,
                    uint32_t *pool, int *head)
{
    int sq_id = threadIdx.x;
    int nbas = envs.nbas;
    int *bas = envs.bas;
    double *env = envs.env;
    int nroots = bounds.nroots;
    int nsq_per_block = blockDim.x;
    int gout_stride = blockDim.y;
    extern __shared__ double shared_memory[];
    double *rw = shared_memory + sq_id;
    double *cicj_cache = shared_memory + nsq_per_block * (nroots*2);
    int t_id = threadIdx.y * nsq_per_block + threadIdx.x;
    int threads = nsq_per_block * gout_stride;

    uint32_t *bas_kl_idx = pool + blockIdx.x * QUEUE_DEPTH;
    __shared__ int ntasks, pair_ij, pair_kl0;
while (1) {
    __syncthreads();
    __shared__ int ish, jsh;
    if (sq_id == 0) {
        int task_id = atomicAdd(head, 1);
        int batch_kl = task_id / bounds.npairs_ij;
        pair_ij = task_id - bounds.npairs_ij * batch_kl;
        pair_kl0 = batch_kl * (QUEUE_DEPTH - 512);
        uint32_t bas_ij = bounds.pair_ij_mapping[pair_ij];
        ish = bas_ij / nbas;
        jsh = bas_ij % nbas;
    }
    __syncthreads();
    if (pair_kl0 >= bounds.npairs_kl) {
        break;
    }
    if (jk.lr_factor != 0) {
        _fill_vjk_tasks_nosym(ntasks, pair_kl0, bas_kl_idx, pair_ij, ish, jsh,
                              q_cond_ij, q_cond_kl, dm_penalty, envs, bounds);
    } else {
        _fill_sr_vjk_tasks_nosym(ntasks, pair_kl0, bas_kl_idx, pair_ij, ish, jsh,
                                 q_cond_ij, q_cond_kl, dm_penalty,
                                 s_cond_ij, s_cond_kl, diffuse_exps, envs, bounds);
    }
    if (ntasks == 0) {
        continue;
    }
    __shared__ double ri[3];
    __shared__ double rjri[3];
    __shared__ double aij_cache[3];
    __shared__ int expi;
    __shared__ int expj;
    if (t_id == 0) {
        expi = bas[ish*BAS_SLOTS+PTR_EXP];
        expj = bas[jsh*BAS_SLOTS+PTR_EXP];
    }
    __syncthreads();
    if (t_id < 3) {
        int ri_ptr = bas[ish*BAS_SLOTS+PTR_BAS_COORD];
        int rj_ptr = bas[jsh*BAS_SLOTS+PTR_BAS_COORD];
        ri[t_id] = env[ri_ptr+t_id];
        rjri[t_id] = env[rj_ptr+t_id] - ri[t_id];
    }
    __syncthreads();
    double *ci = env + bas[ish*BAS_SLOTS+PTR_COEFF];
    double *cj = env + bas[jsh*BAS_SLOTS+PTR_COEFF];
    double xjxi = rjri[0];
    double yjyi = rjri[1];
    double zjzi = rjri[2];
    int iprim = bounds.iprim;
    int jprim = bounds.jprim;
    for (int ij = t_id; ij < iprim*jprim; ij += threads) {
        int ip = ij / jprim;
        int jp = ij % jprim;
        double ai = env[expi+ip];
        double aj = env[expj+jp];
        double aij = ai + aj;
        double theta_ij = ai * aj / aij;
        double rr_ij = xjxi*xjxi + yjyi*yjyi + zjzi*zjzi;
        double Kab = exp(-theta_ij * rr_ij);
        cicj_cache[ij] = ci[ip] * cj[jp] * Kab;
    }
    __syncthreads();
    for (int task_id = sq_id; task_id < ntasks+sq_id; task_id += nsq_per_block) {
        int iprim = bounds.iprim;
        int jprim = bounds.jprim;
        int kprim = bounds.kprim;
        int lprim = bounds.lprim;
        uint32_t bas_kl = bas_kl_idx[task_id];
        int ksh = bas_kl / nbas;
        int lsh = bas_kl % nbas;
        int expk = bas[ksh*BAS_SLOTS+PTR_EXP];
        int expl = bas[lsh*BAS_SLOTS+PTR_EXP];
        int ck = bas[ksh*BAS_SLOTS+PTR_COEFF];
        int cl = bas[lsh*BAS_SLOTS+PTR_COEFF];
        int rk = bas[ksh*BAS_SLOTS+PTR_BAS_COORD];
        int rl = bas[lsh*BAS_SLOTS+PTR_BAS_COORD];
        double xlxk = env[rl+0] - env[rk+0];
        double ylyk = env[rl+1] - env[rk+1];
        double zlzk = env[rl+2] - env[rk+2];
        double goutx[27];
        double gouty[27];
        double goutz[27];
        #pragma unroll
        for (int n = 0; n < 27; ++n) {
            goutx[n] = 0;
            gouty[n] = 0;
            goutz[n] = 0;
        }
        for (int klp = 0; klp < kprim*lprim; ++klp) {
            int kp = klp / lprim;
            int lp = klp % lprim;
            double ak = env[expk+kp];
            double al = env[expl+lp];
            double akl = ak + al;
            double al_akl = al / akl;
            double theta_kl = ak * al_akl;
            double fac_sym = PI_FAC;
            if (task_id < ntasks) {
                if (ksh == lsh) fac_sym *= .5;
            } else {
                fac_sym = 0;
            }
            double Kcd = exp(-theta_kl * (xlxk*xlxk+ylyk*ylyk+zlzk*zlzk));
            double ckcl = fac_sym * env[ck+kp] * env[cl+lp] * Kcd;
            for (int ijp = 0; ijp < iprim*jprim; ++ijp) {
                int ip = ijp / jprim;
                int jp = ijp % jprim;
                double ai = env[expi+ip];
                double aj = env[expj+jp];
                double aij = ai + aj;
                double aj_aij = aj / aij;
                double cicj = cicj_cache[ijp];
                double fac = cicj * ckcl / (aij*akl*sqrt(aij+akl));
                __syncthreads();
                if (sq_id == 0) {
                    aij_cache[0] = aij;
                    aij_cache[1] = aj_aij;
                    aij_cache[2] = ai * 2;
                }
                double xpa = rjri[0] * aj_aij;
                double ypa = rjri[1] * aj_aij;
                double zpa = rjri[2] * aj_aij;
                double xij = ri[0] + xpa;
                double yij = ri[1] + ypa;
                double zij = ri[2] + zpa;
                double xqc = xlxk * al_akl;
                double yqc = ylyk * al_akl;
                double zqc = zlzk * al_akl;
                double xkl = env[rk+0] + xqc;
                double ykl = env[rk+1] + yqc;
                double zkl = env[rk+2] + zqc;
                double xpq = xij - xkl;
                double ypq = yij - ykl;
                double zpq = zij - zkl;
                double theta = aij * akl / (aij + akl);
                double rr = xpq * xpq + ypq * ypq + zpq * zpq;
                int nroots = bounds.nroots;
                rys_roots_rs(nroots, theta, rr, jk.omega, rw, nsq_per_block, 0, 1);
                if (task_id >= ntasks) {
                    continue;
                }
                for (int irys = 0; irys < nroots; ++irys) {
                    double wt = rw[(2*irys+1)*nsq_per_block] * fac;
                    double rt = rw[ 2*irys   *nsq_per_block];
                    double aij = aij_cache[0];
                    double rt_aa = rt / (aij + akl);
                    double b00 = .5 * rt_aa;
                    double fx, fy, fz;
                    double rt_akl = rt_aa * aij;
                    double b01 = .5/akl * (1 - rt_akl);
                    double cpx = xqc + xpq*rt_akl;
                    double rt_aij = rt_aa * akl;
                    double b10 = .5/aij * (1 - rt_aij);
                    double c0x = rjri[0] * aij_cache[1] - xpq*rt_aij;
                    double trr_10x = c0x * 1;
                    double trr_20x = c0x * trr_10x + 1*b10 * 1;
                    double trr_21x = cpx * trr_20x + 2*b00 * trr_10x;
                    double trr_11x = cpx * trr_10x + 1*b00 * 1;
                    double trr_22x = cpx * trr_21x + 1*b01 * trr_20x + 2*b00 * trr_11x;
                    double hrr_2011x = trr_22x - xlxk * trr_21x;
                    fx = aij_cache[2] * hrr_2011x;
                    double c0y = rjri[1] * aij_cache[1] - ypq*rt_aij;
                    double trr_10y = c0y * 1;
                    fy = aij_cache[2] * trr_10y;
                    double c0z = rjri[2] * aij_cache[1] - zpq*rt_aij;
                    double trr_10z = c0z * wt;
                    fz = aij_cache[2] * trr_10z;
                    double trr_01x = cpx * 1;
                    double trr_02x = cpx * trr_01x + 1*b01 * 1;
                    double hrr_0011x = trr_02x - xlxk * trr_01x;
                    fx -= 1 * hrr_0011x;
                    double trr_12x = cpx * trr_11x + 1*b01 * trr_10x + 1*b00 * trr_01x;
                    double hrr_1011x = trr_12x - xlxk * trr_11x;
                    goutx[0] +=  fx  * 1 * wt;
                    gouty[0] += hrr_1011x *  fy  * wt;
                    goutz[0] += hrr_1011x * 1 *  fz ;
                    fx = aij_cache[2] * hrr_1011x;
                    double trr_20y = c0y * trr_10y + 1*b10 * 1;
                    fy = aij_cache[2] * trr_20y;
                    fz = aij_cache[2] * trr_10z;
                    fy -= 1 * 1;
                    goutx[1] +=  fx  * trr_10y * wt;
                    gouty[1] += hrr_0011x *  fy  * wt;
                    goutz[1] += hrr_0011x * trr_10y *  fz ;
                    fx = aij_cache[2] * hrr_1011x;
                    fy = aij_cache[2] * trr_10y;
                    double trr_20z = c0z * trr_10z + 1*b10 * wt;
                    fz = aij_cache[2] * trr_20z;
                    fz -= 1 * wt;
                    goutx[2] +=  fx  * 1 * trr_10z;
                    gouty[2] += hrr_0011x *  fy  * trr_10z;
                    goutz[2] += hrr_0011x * 1 *  fz ;
                    double hrr_2001x = trr_21x - xlxk * trr_20x;
                    fx = aij_cache[2] * hrr_2001x;
                    double cpy = yqc + ypq*rt_akl;
                    double trr_11y = cpy * trr_10y + 1*b00 * 1;
                    fy = aij_cache[2] * trr_11y;
                    fz = aij_cache[2] * trr_10z;
                    double hrr_0001x = trr_01x - xlxk * 1;
                    fx -= 1 * hrr_0001x;
                    double hrr_1001x = trr_11x - xlxk * trr_10x;
                    double trr_01y = cpy * 1;
                    goutx[3] +=  fx  * trr_01y * wt;
                    gouty[3] += hrr_1001x *  fy  * wt;
                    goutz[3] += hrr_1001x * trr_01y *  fz ;
                    fx = aij_cache[2] * hrr_1001x;
                    double trr_21y = cpy * trr_20y + 2*b00 * trr_10y;
                    fy = aij_cache[2] * trr_21y;
                    fz = aij_cache[2] * trr_10z;
                    fy -= 1 * trr_01y;
                    goutx[4] +=  fx  * trr_11y * wt;
                    gouty[4] += hrr_0001x *  fy  * wt;
                    goutz[4] += hrr_0001x * trr_11y *  fz ;
                    fx = aij_cache[2] * hrr_1001x;
                    fy = aij_cache[2] * trr_11y;
                    fz = aij_cache[2] * trr_20z;
                    fz -= 1 * wt;
                    goutx[5] +=  fx  * trr_01y * trr_10z;
                    gouty[5] += hrr_0001x *  fy  * trr_10z;
                    goutz[5] += hrr_0001x * trr_01y *  fz ;
                    fx = aij_cache[2] * hrr_2001x;
                    fy = aij_cache[2] * trr_10y;
                    double cpz = zqc + zpq*rt_akl;
                    double trr_11z = cpz * trr_10z + 1*b00 * wt;
                    fz = aij_cache[2] * trr_11z;
                    fx -= 1 * hrr_0001x;
                    double trr_01z = cpz * wt;
                    goutx[6] +=  fx  * 1 * trr_01z;
                    gouty[6] += hrr_1001x *  fy  * trr_01z;
                    goutz[6] += hrr_1001x * 1 *  fz ;
                    fx = aij_cache[2] * hrr_1001x;
                    fy = aij_cache[2] * trr_20y;
                    fz = aij_cache[2] * trr_11z;
                    fy -= 1 * 1;
                    goutx[7] +=  fx  * trr_10y * trr_01z;
                    gouty[7] += hrr_0001x *  fy  * trr_01z;
                    goutz[7] += hrr_0001x * trr_10y *  fz ;
                    fx = aij_cache[2] * hrr_1001x;
                    fy = aij_cache[2] * trr_10y;
                    double trr_21z = cpz * trr_20z + 2*b00 * trr_10z;
                    fz = aij_cache[2] * trr_21z;
                    fz -= 1 * trr_01z;
                    goutx[8] +=  fx  * 1 * trr_11z;
                    gouty[8] += hrr_0001x *  fy  * trr_11z;
                    goutz[8] += hrr_0001x * 1 *  fz ;
                    fx = aij_cache[2] * trr_21x;
                    double hrr_1001y = trr_11y - ylyk * trr_10y;
                    fy = aij_cache[2] * hrr_1001y;
                    fz = aij_cache[2] * trr_10z;
                    fx -= 1 * trr_01x;
                    double hrr_0001y = trr_01y - ylyk * 1;
                    goutx[9] +=  fx  * hrr_0001y * wt;
                    gouty[9] += trr_11x *  fy  * wt;
                    goutz[9] += trr_11x * hrr_0001y *  fz ;
                    fx = aij_cache[2] * trr_11x;
                    double hrr_2001y = trr_21y - ylyk * trr_20y;
                    fy = aij_cache[2] * hrr_2001y;
                    fz = aij_cache[2] * trr_10z;
                    fy -= 1 * hrr_0001y;
                    goutx[10] +=  fx  * hrr_1001y * wt;
                    gouty[10] += trr_01x *  fy  * wt;
                    goutz[10] += trr_01x * hrr_1001y *  fz ;
                    fx = aij_cache[2] * trr_11x;
                    fy = aij_cache[2] * hrr_1001y;
                    fz = aij_cache[2] * trr_20z;
                    fz -= 1 * wt;
                    goutx[11] +=  fx  * hrr_0001y * trr_10z;
                    gouty[11] += trr_01x *  fy  * trr_10z;
                    goutz[11] += trr_01x * hrr_0001y *  fz ;
                    fx = aij_cache[2] * trr_20x;
                    double trr_12y = cpy * trr_11y + 1*b01 * trr_10y + 1*b00 * trr_01y;
                    double hrr_1011y = trr_12y - ylyk * trr_11y;
                    fy = aij_cache[2] * hrr_1011y;
                    fz = aij_cache[2] * trr_10z;
                    fx -= 1 * 1;
                    double trr_02y = cpy * trr_01y + 1*b01 * 1;
                    double hrr_0011y = trr_02y - ylyk * trr_01y;
                    goutx[12] +=  fx  * hrr_0011y * wt;
                    gouty[12] += trr_10x *  fy  * wt;
                    goutz[12] += trr_10x * hrr_0011y *  fz ;
                    fx = aij_cache[2] * trr_10x;
                    double trr_22y = cpy * trr_21y + 1*b01 * trr_20y + 2*b00 * trr_11y;
                    double hrr_2011y = trr_22y - ylyk * trr_21y;
                    fy = aij_cache[2] * hrr_2011y;
                    fz = aij_cache[2] * trr_10z;
                    fy -= 1 * hrr_0011y;
                    goutx[13] +=  fx  * hrr_1011y * wt;
                    gouty[13] += 1 *  fy  * wt;
                    goutz[13] += 1 * hrr_1011y *  fz ;
                    fx = aij_cache[2] * trr_10x;
                    fy = aij_cache[2] * hrr_1011y;
                    fz = aij_cache[2] * trr_20z;
                    fz -= 1 * wt;
                    goutx[14] +=  fx  * hrr_0011y * trr_10z;
                    gouty[14] += 1 *  fy  * trr_10z;
                    goutz[14] += 1 * hrr_0011y *  fz ;
                    fx = aij_cache[2] * trr_20x;
                    fy = aij_cache[2] * hrr_1001y;
                    fz = aij_cache[2] * trr_11z;
                    fx -= 1 * 1;
                    goutx[15] +=  fx  * hrr_0001y * trr_01z;
                    gouty[15] += trr_10x *  fy  * trr_01z;
                    goutz[15] += trr_10x * hrr_0001y *  fz ;
                    fx = aij_cache[2] * trr_10x;
                    fy = aij_cache[2] * hrr_2001y;
                    fz = aij_cache[2] * trr_11z;
                    fy -= 1 * hrr_0001y;
                    goutx[16] +=  fx  * hrr_1001y * trr_01z;
                    gouty[16] += 1 *  fy  * trr_01z;
                    goutz[16] += 1 * hrr_1001y *  fz ;
                    fx = aij_cache[2] * trr_10x;
                    fy = aij_cache[2] * hrr_1001y;
                    fz = aij_cache[2] * trr_21z;
                    fz -= 1 * trr_01z;
                    goutx[17] +=  fx  * hrr_0001y * trr_11z;
                    gouty[17] += 1 *  fy  * trr_11z;
                    goutz[17] += 1 * hrr_0001y *  fz ;
                    fx = aij_cache[2] * trr_21x;
                    fy = aij_cache[2] * trr_10y;
                    double hrr_1001z = trr_11z - zlzk * trr_10z;
                    fz = aij_cache[2] * hrr_1001z;
                    fx -= 1 * trr_01x;
                    double hrr_0001z = trr_01z - zlzk * wt;
                    goutx[18] +=  fx  * 1 * hrr_0001z;
                    gouty[18] += trr_11x *  fy  * hrr_0001z;
                    goutz[18] += trr_11x * 1 *  fz ;
                    fx = aij_cache[2] * trr_11x;
                    fy = aij_cache[2] * trr_20y;
                    fz = aij_cache[2] * hrr_1001z;
                    fy -= 1 * 1;
                    goutx[19] +=  fx  * trr_10y * hrr_0001z;
                    gouty[19] += trr_01x *  fy  * hrr_0001z;
                    goutz[19] += trr_01x * trr_10y *  fz ;
                    fx = aij_cache[2] * trr_11x;
                    fy = aij_cache[2] * trr_10y;
                    double hrr_2001z = trr_21z - zlzk * trr_20z;
                    fz = aij_cache[2] * hrr_2001z;
                    fz -= 1 * hrr_0001z;
