                atomicAdd(vk_z+(i0+1)*nao+(k0+0), vzik_10);
                double vxik_11 = goutx[4]*dm_jl_00 + goutx[13]*dm_jl_01 + goutx[22]*dm_jl_02;
                atomicAdd(vk_x+(i0+1)*nao+(k0+1), vxik_11);
                double vyik_11 = gouty[4]*dm_jl_00 + gouty[13]*dm_jl_01 + gouty[22]*dm_jl_02;
                atomicAdd(vk_y+(i0+1)*nao+(k0+1), vyik_11);
                double vzik_11 = goutz[4]*dm_jl_00 + goutz[13]*dm_jl_01 + goutz[22]*dm_jl_02;
                atomicAdd(vk_z+(i0+1)*nao+(k0+1), vzik_11);
                double vxik_12 = goutx[7]*dm_jl_00 + goutx[16]*dm_jl_01 + goutx[25]*dm_jl_02;
                atomicAdd(vk_x+(i0+1)*nao+(k0+2), vxik_12);
                double vyik_12 = gouty[7]*dm_jl_00 + gouty[16]*dm_jl_01 + gouty[25]*dm_jl_02;
                atomicAdd(vk_y+(i0+1)*nao+(k0+2), vyik_12);
                double vzik_12 = goutz[7]*dm_jl_00 + goutz[16]*dm_jl_01 + goutz[25]*dm_jl_02;
                atomicAdd(vk_z+(i0+1)*nao+(k0+2), vzik_12);
                double vxik_20 = goutx[2]*dm_jl_00 + goutx[11]*dm_jl_01 + goutx[20]*dm_jl_02;
                atomicAdd(vk_x+(i0+2)*nao+(k0+0), vxik_20);
                double vyik_20 = gouty[2]*dm_jl_00 + gouty[11]*dm_jl_01 + gouty[20]*dm_jl_02;
                atomicAdd(vk_y+(i0+2)*nao+(k0+0), vyik_20);
                double vzik_20 = goutz[2]*dm_jl_00 + goutz[11]*dm_jl_01 + goutz[20]*dm_jl_02;
                atomicAdd(vk_z+(i0+2)*nao+(k0+0), vzik_20);
                double vxik_21 = goutx[5]*dm_jl_00 + goutx[14]*dm_jl_01 + goutx[23]*dm_jl_02;
                atomicAdd(vk_x+(i0+2)*nao+(k0+1), vxik_21);
                double vyik_21 = gouty[5]*dm_jl_00 + gouty[14]*dm_jl_01 + gouty[23]*dm_jl_02;
                atomicAdd(vk_y+(i0+2)*nao+(k0+1), vyik_21);
                double vzik_21 = goutz[5]*dm_jl_00 + goutz[14]*dm_jl_01 + goutz[23]*dm_jl_02;
                atomicAdd(vk_z+(i0+2)*nao+(k0+1), vzik_21);
                double vxik_22 = goutx[8]*dm_jl_00 + goutx[17]*dm_jl_01 + goutx[26]*dm_jl_02;
                atomicAdd(vk_x+(i0+2)*nao+(k0+2), vxik_22);
                double vyik_22 = gouty[8]*dm_jl_00 + gouty[17]*dm_jl_01 + gouty[26]*dm_jl_02;
                atomicAdd(vk_y+(i0+2)*nao+(k0+2), vyik_22);
                double vzik_22 = goutz[8]*dm_jl_00 + goutz[17]*dm_jl_01 + goutz[26]*dm_jl_02;
                atomicAdd(vk_z+(i0+2)*nao+(k0+2), vzik_22);
                double dm_ik_00 = dm[(i0+0)*nao+(k0+0)];
                double dm_ik_10 = dm[(i0+1)*nao+(k0+0)];
                double dm_ik_20 = dm[(i0+2)*nao+(k0+0)];
                double dm_ik_01 = dm[(i0+0)*nao+(k0+1)];
                double dm_ik_11 = dm[(i0+1)*nao+(k0+1)];
                double dm_ik_21 = dm[(i0+2)*nao+(k0+1)];
                double dm_ik_02 = dm[(i0+0)*nao+(k0+2)];
                double dm_ik_12 = dm[(i0+1)*nao+(k0+2)];
                double dm_ik_22 = dm[(i0+2)*nao+(k0+2)];
                double vxjl_00 = goutx[0]*dm_ik_00 + goutx[1]*dm_ik_10 + goutx[2]*dm_ik_20 + goutx[3]*dm_ik_01 + goutx[4]*dm_ik_11 + goutx[5]*dm_ik_21 + goutx[6]*dm_ik_02 + goutx[7]*dm_ik_12 + goutx[8]*dm_ik_22;
                atomicAdd(vk_x+(j0+0)*nao+(l0+0), vxjl_00);
                double vyjl_00 = gouty[0]*dm_ik_00 + gouty[1]*dm_ik_10 + gouty[2]*dm_ik_20 + gouty[3]*dm_ik_01 + gouty[4]*dm_ik_11 + gouty[5]*dm_ik_21 + gouty[6]*dm_ik_02 + gouty[7]*dm_ik_12 + gouty[8]*dm_ik_22;
                atomicAdd(vk_y+(j0+0)*nao+(l0+0), vyjl_00);
                double vzjl_00 = goutz[0]*dm_ik_00 + goutz[1]*dm_ik_10 + goutz[2]*dm_ik_20 + goutz[3]*dm_ik_01 + goutz[4]*dm_ik_11 + goutz[5]*dm_ik_21 + goutz[6]*dm_ik_02 + goutz[7]*dm_ik_12 + goutz[8]*dm_ik_22;
                atomicAdd(vk_z+(j0+0)*nao+(l0+0), vzjl_00);
                double vxjl_01 = goutx[9]*dm_ik_00 + goutx[10]*dm_ik_10 + goutx[11]*dm_ik_20 + goutx[12]*dm_ik_01 + goutx[13]*dm_ik_11 + goutx[14]*dm_ik_21 + goutx[15]*dm_ik_02 + goutx[16]*dm_ik_12 + goutx[17]*dm_ik_22;
                atomicAdd(vk_x+(j0+0)*nao+(l0+1), vxjl_01);
                double vyjl_01 = gouty[9]*dm_ik_00 + gouty[10]*dm_ik_10 + gouty[11]*dm_ik_20 + gouty[12]*dm_ik_01 + gouty[13]*dm_ik_11 + gouty[14]*dm_ik_21 + gouty[15]*dm_ik_02 + gouty[16]*dm_ik_12 + gouty[17]*dm_ik_22;
                atomicAdd(vk_y+(j0+0)*nao+(l0+1), vyjl_01);
                double vzjl_01 = goutz[9]*dm_ik_00 + goutz[10]*dm_ik_10 + goutz[11]*dm_ik_20 + goutz[12]*dm_ik_01 + goutz[13]*dm_ik_11 + goutz[14]*dm_ik_21 + goutz[15]*dm_ik_02 + goutz[16]*dm_ik_12 + goutz[17]*dm_ik_22;
                atomicAdd(vk_z+(j0+0)*nao+(l0+1), vzjl_01);
                double vxjl_02 = goutx[18]*dm_ik_00 + goutx[19]*dm_ik_10 + goutx[20]*dm_ik_20 + goutx[21]*dm_ik_01 + goutx[22]*dm_ik_11 + goutx[23]*dm_ik_21 + goutx[24]*dm_ik_02 + goutx[25]*dm_ik_12 + goutx[26]*dm_ik_22;
                atomicAdd(vk_x+(j0+0)*nao+(l0+2), vxjl_02);
                double vyjl_02 = gouty[18]*dm_ik_00 + gouty[19]*dm_ik_10 + gouty[20]*dm_ik_20 + gouty[21]*dm_ik_01 + gouty[22]*dm_ik_11 + gouty[23]*dm_ik_21 + gouty[24]*dm_ik_02 + gouty[25]*dm_ik_12 + gouty[26]*dm_ik_22;
                atomicAdd(vk_y+(j0+0)*nao+(l0+2), vyjl_02);
                double vzjl_02 = goutz[18]*dm_ik_00 + goutz[19]*dm_ik_10 + goutz[20]*dm_ik_20 + goutz[21]*dm_ik_01 + goutz[22]*dm_ik_11 + goutz[23]*dm_ik_21 + goutz[24]*dm_ik_02 + goutz[25]*dm_ik_12 + goutz[26]*dm_ik_22;
                atomicAdd(vk_z+(j0+0)*nao+(l0+2), vzjl_02);
                double dm_il_00 = dm[(i0+0)*nao+(l0+0)];
                double dm_il_10 = dm[(i0+1)*nao+(l0+0)];
                double dm_il_20 = dm[(i0+2)*nao+(l0+0)];
                double dm_il_01 = dm[(i0+0)*nao+(l0+1)];
                double dm_il_11 = dm[(i0+1)*nao+(l0+1)];
                double dm_il_21 = dm[(i0+2)*nao+(l0+1)];
                double dm_il_02 = dm[(i0+0)*nao+(l0+2)];
                double dm_il_12 = dm[(i0+1)*nao+(l0+2)];
                double dm_il_22 = dm[(i0+2)*nao+(l0+2)];
                double vxjk_00 = goutx[0]*dm_il_00 + goutx[1]*dm_il_10 + goutx[2]*dm_il_20 + goutx[9]*dm_il_01 + goutx[10]*dm_il_11 + goutx[11]*dm_il_21 + goutx[18]*dm_il_02 + goutx[19]*dm_il_12 + goutx[20]*dm_il_22;
                atomicAdd(vk_x+(j0+0)*nao+(k0+0), vxjk_00);
                double vyjk_00 = gouty[0]*dm_il_00 + gouty[1]*dm_il_10 + gouty[2]*dm_il_20 + gouty[9]*dm_il_01 + gouty[10]*dm_il_11 + gouty[11]*dm_il_21 + gouty[18]*dm_il_02 + gouty[19]*dm_il_12 + gouty[20]*dm_il_22;
                atomicAdd(vk_y+(j0+0)*nao+(k0+0), vyjk_00);
                double vzjk_00 = goutz[0]*dm_il_00 + goutz[1]*dm_il_10 + goutz[2]*dm_il_20 + goutz[9]*dm_il_01 + goutz[10]*dm_il_11 + goutz[11]*dm_il_21 + goutz[18]*dm_il_02 + goutz[19]*dm_il_12 + goutz[20]*dm_il_22;
                atomicAdd(vk_z+(j0+0)*nao+(k0+0), vzjk_00);
                double vxjk_01 = goutx[3]*dm_il_00 + goutx[4]*dm_il_10 + goutx[5]*dm_il_20 + goutx[12]*dm_il_01 + goutx[13]*dm_il_11 + goutx[14]*dm_il_21 + goutx[21]*dm_il_02 + goutx[22]*dm_il_12 + goutx[23]*dm_il_22;
                atomicAdd(vk_x+(j0+0)*nao+(k0+1), vxjk_01);
                double vyjk_01 = gouty[3]*dm_il_00 + gouty[4]*dm_il_10 + gouty[5]*dm_il_20 + gouty[12]*dm_il_01 + gouty[13]*dm_il_11 + gouty[14]*dm_il_21 + gouty[21]*dm_il_02 + gouty[22]*dm_il_12 + gouty[23]*dm_il_22;
                atomicAdd(vk_y+(j0+0)*nao+(k0+1), vyjk_01);
                double vzjk_01 = goutz[3]*dm_il_00 + goutz[4]*dm_il_10 + goutz[5]*dm_il_20 + goutz[12]*dm_il_01 + goutz[13]*dm_il_11 + goutz[14]*dm_il_21 + goutz[21]*dm_il_02 + goutz[22]*dm_il_12 + goutz[23]*dm_il_22;
                atomicAdd(vk_z+(j0+0)*nao+(k0+1), vzjk_01);
                double vxjk_02 = goutx[6]*dm_il_00 + goutx[7]*dm_il_10 + goutx[8]*dm_il_20 + goutx[15]*dm_il_01 + goutx[16]*dm_il_11 + goutx[17]*dm_il_21 + goutx[24]*dm_il_02 + goutx[25]*dm_il_12 + goutx[26]*dm_il_22;
                atomicAdd(vk_x+(j0+0)*nao+(k0+2), vxjk_02);
                double vyjk_02 = gouty[6]*dm_il_00 + gouty[7]*dm_il_10 + gouty[8]*dm_il_20 + gouty[15]*dm_il_01 + gouty[16]*dm_il_11 + gouty[17]*dm_il_21 + gouty[24]*dm_il_02 + gouty[25]*dm_il_12 + gouty[26]*dm_il_22;
                atomicAdd(vk_y+(j0+0)*nao+(k0+2), vyjk_02);
                double vzjk_02 = goutz[6]*dm_il_00 + goutz[7]*dm_il_10 + goutz[8]*dm_il_20 + goutz[15]*dm_il_01 + goutz[16]*dm_il_11 + goutz[17]*dm_il_21 + goutz[24]*dm_il_02 + goutz[25]*dm_il_12 + goutz[26]*dm_il_22;
                atomicAdd(vk_z+(j0+0)*nao+(k0+2), vzjk_02);
            }
        }
    }
}
}

__global__ static
void rys_vjk_ip1_1020(RysIntEnvVars envs, JKMatrix jk, BoundsInfo bounds,
                    float *q_cond_ij, float *q_cond_kl, float dm_penalty,
                    float *s_cond_ij, float *s_cond_kl, float *diffuse_exps,
                    uint32_t *pool, int *head)
{
    int sq_id = threadIdx.x;
    int nbas = envs.nbas;
    int *bas = envs.bas;
    double *env = envs.env;
    int nroots = bounds.nroots;
    int nsq_per_block = blockDim.x;
    int gout_stride = blockDim.y;
    extern __shared__ double shared_memory[];
    double *rw = shared_memory + sq_id;
    double *cicj_cache = shared_memory + nsq_per_block * (nroots*2);
    int t_id = threadIdx.y * nsq_per_block + threadIdx.x;
    int threads = nsq_per_block * gout_stride;

    uint32_t *bas_kl_idx = pool + blockIdx.x * QUEUE_DEPTH;
    __shared__ int ntasks, pair_ij, pair_kl0;
while (1) {
    __syncthreads();
    __shared__ int ish, jsh;
    if (sq_id == 0) {
        int task_id = atomicAdd(head, 1);
        int batch_kl = task_id / bounds.npairs_ij;
        pair_ij = task_id - bounds.npairs_ij * batch_kl;
        pair_kl0 = batch_kl * (QUEUE_DEPTH - 512);
        uint32_t bas_ij = bounds.pair_ij_mapping[pair_ij];
        ish = bas_ij / nbas;
        jsh = bas_ij % nbas;
    }
    __syncthreads();
    if (pair_kl0 >= bounds.npairs_kl) {
        break;
    }
    if (jk.lr_factor != 0) {
        _fill_vjk_tasks_nosym(ntasks, pair_kl0, bas_kl_idx, pair_ij, ish, jsh,
                              q_cond_ij, q_cond_kl, dm_penalty, envs, bounds);
    } else {
        _fill_sr_vjk_tasks_nosym(ntasks, pair_kl0, bas_kl_idx, pair_ij, ish, jsh,
                                 q_cond_ij, q_cond_kl, dm_penalty,
                                 s_cond_ij, s_cond_kl, diffuse_exps, envs, bounds);
    }
    if (ntasks == 0) {
        continue;
    }
    __shared__ double ri[3];
    __shared__ double rjri[3];
    __shared__ double aij_cache[3];
    __shared__ int expi;
    __shared__ int expj;
    if (t_id == 0) {
        expi = bas[ish*BAS_SLOTS+PTR_EXP];
        expj = bas[jsh*BAS_SLOTS+PTR_EXP];
    }
    __syncthreads();
    if (t_id < 3) {
        int ri_ptr = bas[ish*BAS_SLOTS+PTR_BAS_COORD];
        int rj_ptr = bas[jsh*BAS_SLOTS+PTR_BAS_COORD];
        ri[t_id] = env[ri_ptr+t_id];
        rjri[t_id] = env[rj_ptr+t_id] - ri[t_id];
    }
    __syncthreads();
    double *ci = env + bas[ish*BAS_SLOTS+PTR_COEFF];
    double *cj = env + bas[jsh*BAS_SLOTS+PTR_COEFF];
    double xjxi = rjri[0];
    double yjyi = rjri[1];
    double zjzi = rjri[2];
    int iprim = bounds.iprim;
    int jprim = bounds.jprim;
    for (int ij = t_id; ij < iprim*jprim; ij += threads) {
        int ip = ij / jprim;
        int jp = ij % jprim;
        double ai = env[expi+ip];
        double aj = env[expj+jp];
        double aij = ai + aj;
        double theta_ij = ai * aj / aij;
        double rr_ij = xjxi*xjxi + yjyi*yjyi + zjzi*zjzi;
        double Kab = exp(-theta_ij * rr_ij);
        cicj_cache[ij] = ci[ip] * cj[jp] * Kab;
    }
    __syncthreads();
    for (int task_id = sq_id; task_id < ntasks+sq_id; task_id += nsq_per_block) {
        int iprim = bounds.iprim;
        int jprim = bounds.jprim;
        int kprim = bounds.kprim;
        int lprim = bounds.lprim;
        uint32_t bas_kl = bas_kl_idx[task_id];
        int ksh = bas_kl / nbas;
        int lsh = bas_kl % nbas;
        int expk = bas[ksh*BAS_SLOTS+PTR_EXP];
        int expl = bas[lsh*BAS_SLOTS+PTR_EXP];
        int ck = bas[ksh*BAS_SLOTS+PTR_COEFF];
        int cl = bas[lsh*BAS_SLOTS+PTR_COEFF];
        int rk = bas[ksh*BAS_SLOTS+PTR_BAS_COORD];
        int rl = bas[lsh*BAS_SLOTS+PTR_BAS_COORD];
        double xlxk = env[rl+0] - env[rk+0];
        double ylyk = env[rl+1] - env[rk+1];
        double zlzk = env[rl+2] - env[rk+2];
        double goutx[18];
        double gouty[18];
        double goutz[18];
        #pragma unroll
        for (int n = 0; n < 18; ++n) {
            goutx[n] = 0;
            gouty[n] = 0;
            goutz[n] = 0;
        }
        for (int klp = 0; klp < kprim*lprim; ++klp) {
            int kp = klp / lprim;
            int lp = klp % lprim;
            double ak = env[expk+kp];
            double al = env[expl+lp];
            double akl = ak + al;
            double al_akl = al / akl;
            double theta_kl = ak * al_akl;
            double fac_sym = PI_FAC;
            if (task_id < ntasks) {
                if (ksh == lsh) fac_sym *= .5;
            } else {
                fac_sym = 0;
            }
            double Kcd = exp(-theta_kl * (xlxk*xlxk+ylyk*ylyk+zlzk*zlzk));
            double ckcl = fac_sym * env[ck+kp] * env[cl+lp] * Kcd;
            for (int ijp = 0; ijp < iprim*jprim; ++ijp) {
                int ip = ijp / jprim;
                int jp = ijp % jprim;
                double ai = env[expi+ip];
                double aj = env[expj+jp];
                double aij = ai + aj;
                double aj_aij = aj / aij;
                double cicj = cicj_cache[ijp];
                double fac = cicj * ckcl / (aij*akl*sqrt(aij+akl));
                __syncthreads();
                if (sq_id == 0) {
                    aij_cache[0] = aij;
                    aij_cache[1] = aj_aij;
                    aij_cache[2] = ai * 2;
                }
                double xpa = rjri[0] * aj_aij;
                double ypa = rjri[1] * aj_aij;
                double zpa = rjri[2] * aj_aij;
                double xij = ri[0] + xpa;
                double yij = ri[1] + ypa;
                double zij = ri[2] + zpa;
                double xqc = xlxk * al_akl;
                double yqc = ylyk * al_akl;
                double zqc = zlzk * al_akl;
                double xkl = env[rk+0] + xqc;
                double ykl = env[rk+1] + yqc;
                double zkl = env[rk+2] + zqc;
                double xpq = xij - xkl;
                double ypq = yij - ykl;
                double zpq = zij - zkl;
                double theta = aij * akl / (aij + akl);
                double rr = xpq * xpq + ypq * ypq + zpq * zpq;
                int nroots = bounds.nroots;
                rys_roots_rs(nroots, theta, rr, jk.omega, rw, nsq_per_block, 0, 1);
                if (task_id >= ntasks) {
                    continue;
                }
                for (int irys = 0; irys < nroots; ++irys) {
                    double wt = rw[(2*irys+1)*nsq_per_block] * fac;
                    double rt = rw[ 2*irys   *nsq_per_block];
                    double aij = aij_cache[0];
                    double rt_aa = rt / (aij + akl);
                    double b00 = .5 * rt_aa;
                    double fx, fy, fz;
                    double rt_akl = rt_aa * aij;
                    double b01 = .5/akl * (1 - rt_akl);
                    double cpx = xqc + xpq*rt_akl;
                    double rt_aij = rt_aa * akl;
                    double b10 = .5/aij * (1 - rt_aij);
                    double c0x = rjri[0] * aij_cache[1] - xpq*rt_aij;
                    double trr_10x = c0x * 1;
                    double trr_20x = c0x * trr_10x + 1*b10 * 1;
                    double trr_21x = cpx * trr_20x + 2*b00 * trr_10x;
                    double trr_11x = cpx * trr_10x + 1*b00 * 1;
                    double trr_22x = cpx * trr_21x + 1*b01 * trr_20x + 2*b00 * trr_11x;
                    fx = aij_cache[2] * trr_22x;
                    double c0y = rjri[1] * aij_cache[1] - ypq*rt_aij;
                    double trr_10y = c0y * 1;
                    fy = aij_cache[2] * trr_10y;
                    double c0z = rjri[2] * aij_cache[1] - zpq*rt_aij;
                    double trr_10z = c0z * wt;
                    fz = aij_cache[2] * trr_10z;
                    double trr_01x = cpx * 1;
                    double trr_02x = cpx * trr_01x + 1*b01 * 1;
                    fx -= 1 * trr_02x;
                    double trr_12x = cpx * trr_11x + 1*b01 * trr_10x + 1*b00 * trr_01x;
                    goutx[0] +=  fx  * 1 * wt;
                    gouty[0] += trr_12x *  fy  * wt;
                    goutz[0] += trr_12x * 1 *  fz ;
                    fx = aij_cache[2] * trr_12x;
                    double trr_20y = c0y * trr_10y + 1*b10 * 1;
                    fy = aij_cache[2] * trr_20y;
                    fz = aij_cache[2] * trr_10z;
                    fy -= 1 * 1;
                    goutx[1] +=  fx  * trr_10y * wt;
                    gouty[1] += trr_02x *  fy  * wt;
                    goutz[1] += trr_02x * trr_10y *  fz ;
                    fx = aij_cache[2] * trr_12x;
                    fy = aij_cache[2] * trr_10y;
                    double trr_20z = c0z * trr_10z + 1*b10 * wt;
                    fz = aij_cache[2] * trr_20z;
                    fz -= 1 * wt;
                    goutx[2] +=  fx  * 1 * trr_10z;
                    gouty[2] += trr_02x *  fy  * trr_10z;
                    goutz[2] += trr_02x * 1 *  fz ;
                    fx = aij_cache[2] * trr_21x;
                    double cpy = yqc + ypq*rt_akl;
                    double trr_11y = cpy * trr_10y + 1*b00 * 1;
                    fy = aij_cache[2] * trr_11y;
                    fz = aij_cache[2] * trr_10z;
                    fx -= 1 * trr_01x;
                    double trr_01y = cpy * 1;
                    goutx[3] +=  fx  * trr_01y * wt;
                    gouty[3] += trr_11x *  fy  * wt;
                    goutz[3] += trr_11x * trr_01y *  fz ;
                    fx = aij_cache[2] * trr_11x;
                    double trr_21y = cpy * trr_20y + 2*b00 * trr_10y;
                    fy = aij_cache[2] * trr_21y;
