                            gx[3072] = rw[irys*128+64];
                        }
                        double *_gx = gx + n * 1536;
                        double xjxi = rjri[n];
                        double Rpa = xjxi * aij_cache[1];
                        double c0x = Rpa - rt_aij * Rpq[n*64];
                        s0 = _gx[0];
                        s1 = c0x * s0;
