                        s0 = _gx[768];
                        _gx[960] = s1 - xjxi * s0;
                        s1 = _gx[768];
                        s0 = _gx[384];
                        _gx[1152] = s1 - xlxk * s0;
                        s1 = s0;
                        s0 = _gx[0];
                        _gx[768] = s1 - xlxk * s0;
                        s1 = _gx[832];
                        s0 = _gx[448];
                        _gx[1216] = s1 - xlxk * s0;
                        s1 = s0;
                        s0 = _gx[64];
                        _gx[832] = s1 - xlxk * s0;
                        s1 = _gx[896];
                        s0 = _gx[512];
                        _gx[1280] = s1 - xlxk * s0;
                        s1 = s0;
                        s0 = _gx[128];
                        _gx[896] = s1 - xlxk * s0;
                        s1 = _gx[960];
                        s0 = _gx[576];
                        _gx[1344] = s1 - xlxk * s0;
                        s1 = s0;
                        s0 = _gx[192];
                        _gx[960] = s1 - xlxk * s0;
