                atomicAdd(vk_z+(i0+0)*nao+(k0+0), vzik_00);
                double vxik_10 = goutx[1]*dm_jl_00 + goutx[4]*dm_jl_10 + goutx[7]*dm_jl_20 + goutx[10]*dm_jl_30 + goutx[13]*dm_jl_40 + goutx[16]*dm_jl_50;
                atomicAdd(vk_x+(i0+1)*nao+(k0+0), vxik_10);
                double vyik_10 = gouty[1]*dm_jl_00 + gouty[4]*dm_jl_10 + gouty[7]*dm_jl_20 + gouty[10]*dm_jl_30 + gouty[13]*dm_jl_40 + gouty[16]*dm_jl_50;
                atomicAdd(vk_y+(i0+1)*nao+(k0+0), vyik_10);
