                atomicAdd(vj_y+(k0+1)*nao+(l0+0), vykl_10);
                double vzkl_10 = goutz[6]*dm_ji_00 + goutz[7]*dm_ji_01 + goutz[8]*dm_ji_02 + goutz[9]*dm_ji_03 + goutz[10]*dm_ji_04 + goutz[11]*dm_ji_05;
                atomicAdd(vj_z+(k0+1)*nao+(l0+0), vzkl_10);
