                atomicAdd(vk_z+(i0+2)*nao+(l0+0), vzil_20);
                double vxil_30 = goutx[3]*dm_jk_00 + goutx[9]*dm_jk_01 + goutx[15]*dm_jk_02;
                atomicAdd(vk_x+(i0+3)*nao+(l0+0), vxil_30);
