                atomicAdd(vk_z+(j0+3)*nao+(k0+0), vzjk_30);
                double vxjk_40 = goutx[6]*dm_il_20;
                atomicAdd(vk_x+(j0+4)*nao+(k0+0), vxjk_40);
                double vyjk_40 = gouty[6]*dm_il_20;
                atomicAdd(vk_y+(j0+4)*nao+(k0+0), vyjk_40);
                double vzjk_40 = goutz[6]*dm_il_20;
                atomicAdd(vk_z+(j0+4)*nao+(k0+0), vzjk_40);
                double vxjk_50 = goutx[7]*dm_il_00 + goutx[8]*dm_il_40;
                atomicAdd(vk_x+(j0+5)*nao+(k0+0), vxjk_50);
                double vyjk_50 = gouty[7]*dm_il_00 + gouty[8]*dm_il_40;
                atomicAdd(vk_y+(j0+5)*nao+(k0+0), vyjk_50);
                double vzjk_50 = goutz[7]*dm_il_00 + goutz[8]*dm_il_40;
                atomicAdd(vk_z+(j0+5)*nao+(k0+0), vzjk_50);
                break; }
                case 3: {
                double dm_il_30 = dm[(i0+3)*nao+(l0+0)];
                double vxjk_00 = goutx[0]*dm_il_30;
                atomicAdd(vk_x+(j0+0)*nao+(k0+0), vxjk_00);
                double vyjk_00 = gouty[0]*dm_il_30;
                atomicAdd(vk_y+(j0+0)*nao+(k0+0), vyjk_00);
                double vzjk_00 = goutz[0]*dm_il_30;
                atomicAdd(vk_z+(j0+0)*nao+(k0+0), vzjk_00);
                double dm_il_10 = dm[(i0+1)*nao+(l0+0)];
                double dm_il_50 = dm[(i0+5)*nao+(l0+0)];
                double vxjk_10 = goutx[1]*dm_il_10 + goutx[2]*dm_il_50;
                atomicAdd(vk_x+(j0+1)*nao+(k0+0), vxjk_10);
                double vyjk_10 = gouty[1]*dm_il_10 + gouty[2]*dm_il_50;
                atomicAdd(vk_y+(j0+1)*nao+(k0+0), vyjk_10);
                double vzjk_10 = goutz[1]*dm_il_10 + goutz[2]*dm_il_50;
                atomicAdd(vk_z+(j0+1)*nao+(k0+0), vzjk_10);
                double vxjk_20 = goutx[3]*dm_il_30;
                atomicAdd(vk_x+(j0+2)*nao+(k0+0), vxjk_20);
                double vyjk_20 = gouty[3]*dm_il_30;
                atomicAdd(vk_y+(j0+2)*nao+(k0+0), vyjk_20);
                double vzjk_20 = goutz[3]*dm_il_30;
                atomicAdd(vk_z+(j0+2)*nao+(k0+0), vzjk_20);
                double vxjk_30 = goutx[4]*dm_il_10 + goutx[5]*dm_il_50;
                atomicAdd(vk_x+(j0+3)*nao+(k0+0), vxjk_30);
                double vyjk_30 = gouty[4]*dm_il_10 + gouty[5]*dm_il_50;
                atomicAdd(vk_y+(j0+3)*nao+(k0+0), vyjk_30);
                double vzjk_30 = goutz[4]*dm_il_10 + goutz[5]*dm_il_50;
                atomicAdd(vk_z+(j0+3)*nao+(k0+0), vzjk_30);
                double vxjk_40 = goutx[6]*dm_il_30;
                atomicAdd(vk_x+(j0+4)*nao+(k0+0), vxjk_40);
                double vyjk_40 = gouty[6]*dm_il_30;
                atomicAdd(vk_y+(j0+4)*nao+(k0+0), vyjk_40);
                double vzjk_40 = goutz[6]*dm_il_30;
                atomicAdd(vk_z+(j0+4)*nao+(k0+0), vzjk_40);
                double vxjk_50 = goutx[7]*dm_il_10 + goutx[8]*dm_il_50;
                atomicAdd(vk_x+(j0+5)*nao+(k0+0), vxjk_50);
                double vyjk_50 = gouty[7]*dm_il_10 + gouty[8]*dm_il_50;
                atomicAdd(vk_y+(j0+5)*nao+(k0+0), vyjk_50);
                double vzjk_50 = goutz[7]*dm_il_10 + goutz[8]*dm_il_50;
                atomicAdd(vk_z+(j0+5)*nao+(k0+0), vzjk_50);
                break; }
                }
            }
        }
    }
}
}

int rys_vjk_ip1_unrolled(RysIntEnvVars *envs, JKMatrix *jk, BoundsInfo *bounds,
                         float *q_cond_ij, float *q_cond_kl, float dm_penalty,
                         float *s_cond_ij, float *s_cond_kl, float *diffuse_exps,
                         uint32_t *pool, int *head, int workers)
{
    int li = bounds->li;
    int lj = bounds->lj;
    int lk = bounds->lk;
    int ll = bounds->ll;
    int ijkl = li*125 + lj*25 + lk*5 + ll;
    int nroots = bounds->nroots;
    int nsq_per_block = 256;
    int gout_stride = 1;

    switch (ijkl) {
    case 0: // (0, 0, 0, 0)
        adjust_threads(rys_vjk_ip1_0000, nsq_per_block);
        break;
    case 5: // (0, 0, 1, 0)
        adjust_threads(rys_vjk_ip1_0010, nsq_per_block);
        break;
    case 6: // (0, 0, 1, 1)
        adjust_threads(rys_vjk_ip1_0011, nsq_per_block);
        break;
    case 10: // (0, 0, 2, 0)
        adjust_threads(rys_vjk_ip1_0020, nsq_per_block);
        break;
    case 11: // (0, 0, 2, 1)
        adjust_threads(rys_vjk_ip1_0021, nsq_per_block);
        break;
    case 12: // (0, 0, 2, 2)
        break;
    case 25: // (0, 1, 0, 0)
        adjust_threads(rys_vjk_ip1_0100, nsq_per_block);
        break;
    case 30: // (0, 1, 1, 0)
        adjust_threads(rys_vjk_ip1_0110, nsq_per_block);
        break;
    case 31: // (0, 1, 1, 1)
        adjust_threads(rys_vjk_ip1_0111, nsq_per_block);
        break;
    case 35: // (0, 1, 2, 0)
        adjust_threads(rys_vjk_ip1_0120, nsq_per_block);
        break;
    case 36: // (0, 1, 2, 1)
        nsq_per_block = 64;
        gout_stride = 4;
        break;
    case 50: // (0, 2, 0, 0)
        adjust_threads(rys_vjk_ip1_0200, nsq_per_block);
        break;
    case 55: // (0, 2, 1, 0)
        adjust_threads(rys_vjk_ip1_0210, nsq_per_block);
        break;
    case 56: // (0, 2, 1, 1)
        nsq_per_block = 64;
        gout_stride = 4;
        break;
    case 60: // (0, 2, 2, 0)
        nsq_per_block = 64;
        gout_stride = 4;
        break;
    case 125: // (1, 0, 0, 0)
        adjust_threads(rys_vjk_ip1_1000, nsq_per_block);
        break;
    case 130: // (1, 0, 1, 0)
        adjust_threads(rys_vjk_ip1_1010, nsq_per_block);
        break;
    case 131: // (1, 0, 1, 1)
        adjust_threads(rys_vjk_ip1_1011, nsq_per_block);
        break;
    case 135: // (1, 0, 2, 0)
        adjust_threads(rys_vjk_ip1_1020, nsq_per_block);
        break;
    case 136: // (1, 0, 2, 1)
        nsq_per_block = 64;
        gout_stride = 4;
        break;
    case 150: // (1, 1, 0, 0)
        adjust_threads(rys_vjk_ip1_1100, nsq_per_block);
        break;
    case 155: // (1, 1, 1, 0)
        adjust_threads(rys_vjk_ip1_1110, nsq_per_block);
        break;
    case 156: // (1, 1, 1, 1)
        nsq_per_block = 64;
        gout_stride = 4;
        break;
    case 160: // (1, 1, 2, 0)
        nsq_per_block = 64;
        gout_stride = 4;
        break;
    case 175: // (1, 2, 0, 0)
        adjust_threads(rys_vjk_ip1_1200, nsq_per_block);
        break;
    case 180: // (1, 2, 1, 0)
        nsq_per_block = 64;
        gout_stride = 4;
        break;
    case 250: // (2, 0, 0, 0)
        adjust_threads(rys_vjk_ip1_2000, nsq_per_block);
        break;
    case 255: // (2, 0, 1, 0)
        adjust_threads(rys_vjk_ip1_2010, nsq_per_block);
        break;
    case 256: // (2, 0, 1, 1)
        nsq_per_block = 64;
        gout_stride = 4;
        break;
    case 260: // (2, 0, 2, 0)
        nsq_per_block = 64;
        gout_stride = 4;
        break;
    case 275: // (2, 1, 0, 0)
        adjust_threads(rys_vjk_ip1_2100, nsq_per_block);
        break;
    case 280: // (2, 1, 1, 0)
        nsq_per_block = 64;
        gout_stride = 4;
        break;
    case 300: // (2, 2, 0, 0)
        nsq_per_block = 64;
        gout_stride = 4;
        break;
    }

    dim3 threads(nsq_per_block, gout_stride);
    int iprim = bounds->iprim;
    int jprim = bounds->jprim;
    int buflen = nroots*2 * nsq_per_block + iprim*jprim;
    switch (ijkl) {
    case 0: // (0, 0, 0, 0)
        rys_vjk_ip1_0000<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 5: // (0, 0, 1, 0)
        rys_vjk_ip1_0010<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 6: // (0, 0, 1, 1)
        rys_vjk_ip1_0011<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 10: // (0, 0, 2, 0)
        rys_vjk_ip1_0020<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 11: // (0, 0, 2, 1)
        rys_vjk_ip1_0021<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 12: // (0, 0, 2, 2)
        rys_vjk_ip1_0022<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 25: // (0, 1, 0, 0)
        rys_vjk_ip1_0100<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 30: // (0, 1, 1, 0)
        rys_vjk_ip1_0110<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 31: // (0, 1, 1, 1)
        rys_vjk_ip1_0111<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 35: // (0, 1, 2, 0)
        rys_vjk_ip1_0120<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 36: // (0, 1, 2, 1)
        buflen = 5760 + iprim * jprim;
        rys_vjk_ip1_0121<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 50: // (0, 2, 0, 0)
        rys_vjk_ip1_0200<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 55: // (0, 2, 1, 0)
        rys_vjk_ip1_0210<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 56: // (0, 2, 1, 1)
        buflen = 5760 + iprim * jprim;
        rys_vjk_ip1_0211<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 60: // (0, 2, 2, 0)
        buflen = 4608 + iprim * jprim;
        rys_vjk_ip1_0220<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 125: // (1, 0, 0, 0)
        rys_vjk_ip1_1000<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 130: // (1, 0, 1, 0)
        rys_vjk_ip1_1010<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 131: // (1, 0, 1, 1)
        rys_vjk_ip1_1011<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 135: // (1, 0, 2, 0)
        rys_vjk_ip1_1020<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 136: // (1, 0, 2, 1)
        buflen = 4608 + iprim * jprim;
        rys_vjk_ip1_1021<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 150: // (1, 1, 0, 0)
        rys_vjk_ip1_1100<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 155: // (1, 1, 1, 0)
        rys_vjk_ip1_1110<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 156: // (1, 1, 1, 1)
        buflen = 5760 + iprim * jprim;
        rys_vjk_ip1_1111<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 160: // (1, 1, 2, 0)
        buflen = 4608 + iprim * jprim;
        rys_vjk_ip1_1120<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 175: // (1, 2, 0, 0)
        rys_vjk_ip1_1200<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 180: // (1, 2, 1, 0)
        buflen = 4608 + iprim * jprim;
        rys_vjk_ip1_1210<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 250: // (2, 0, 0, 0)
        rys_vjk_ip1_2000<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 255: // (2, 0, 1, 0)
        rys_vjk_ip1_2010<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 256: // (2, 0, 1, 1)
        buflen = 4224 + iprim * jprim;
        rys_vjk_ip1_2011<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 260: // (2, 0, 2, 0)
        buflen = 3456 + iprim * jprim;
        rys_vjk_ip1_2020<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 275: // (2, 1, 0, 0)
        rys_vjk_ip1_2100<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 280: // (2, 1, 1, 0)
        buflen = 4224 + iprim * jprim;
        rys_vjk_ip1_2110<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    case 300: // (2, 2, 0, 0)
        buflen = 3456 + iprim * jprim;
        rys_vjk_ip1_2200<<<workers, threads, buflen*sizeof(double)>>>(
            *envs, *jk, *bounds, q_cond_ij, q_cond_kl, dm_penalty, s_cond_ij, s_cond_kl, diffuse_exps, pool, head); break;
    default: return 0;
    }
    return 1;
}
